INSERT INTO `chatbot_faq` (`id`, `category`, `question`, `answer`, `keywords`, `priority`, `status`, `created_at`, `updated_at`) VALUES
(4, 'Pricing', 'Is there a maintenance fee?', 'Yes, we offer optional Annual Maintenance Plans starting from ₹3,999/year which includes hosting, security updates, backups, and minor changes.', 'maintenance,annual,hosting,support', 3, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(5, 'Services', 'What services do you offer?', 'We offer comprehensive digital solutions: Website Development, Mobile App Development, AI Chatbots, Digital Marketing (SEO, Social Media, Email Marketing), Graphic Design, Video Editing, and Brand Management.', 'services,what,offer,provide', 1, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(6, 'Services', 'Do you build e-commerce websites?', 'Absolutely! We build fully functional e-commerce websites with payment gateway integration, inventory management, order tracking, and customer dashboards.', 'ecommerce,online,shop,store,selling', 2, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(7, 'Services', 'Can you develop custom software?', 'Yes, we develop custom software solutions, CRM systems, ERP systems, and business automation tools tailored to your specific business needs.', 'software,custom,crm,erp,automation', 3, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(8, 'Services', 'Do you provide AI solutions?', 'Yes! We build AI-powered chatbots (like this one!), AI automation tools, predictive analytics, and machine learning solutions for businesses.', 'ai,artificial intelligence,chatbot,automation,ml', 2, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(9, 'Support', 'How do I contact support?', 'You can reach us at:\n📞 Phone: +91 99132 62167\n📧 Email: connect@keryar.com\n🌐 Website: https://keryar.com\n\nOur team responds within 2-4 hours during business hours!', 'contact,support,help,reach,phone,email', 1, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(10, 'Support', 'What are your working hours?', 'We work Monday to Saturday, 10:00 AM to 7:00 PM IST. Emergency support is available 24/7 for critical issues with active maintenance plans.', 'hours,timing,availability,time,open', 2, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(13, 'Company', 'How experienced is your team?', 'Our team has 5+ years of experience in digital solutions. We have successfully delivered 100+ projects across various industries including healthcare, education, e-commerce, and more.', 'experience,team,expertise,portfolio', 2, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(14, 'Company', 'What industries do you work with?', 'We work with diverse industries: Healthcare, Education, E-commerce, Real Estate, Sports, Fashion, Technology, Food & Beverages, Automotive, and more!', 'industry,sector,domain,niche', 3, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(15, 'Timeline', 'How long does website development take?', 'Basic websites: 7-14 days\nCustom websites: 3-6 weeks\nE-commerce sites: 4-8 weeks\n\nTimeline depends on complexity, revisions, and content availability.', 'time,duration,delivery,how long,timeline', 1, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(16, 'Timeline', 'What is the development process?', 'Our process:\n1️⃣ Requirement gathering\n2️⃣ Design & wireframes\n3️⃣ Development\n4️⃣ Testing & review\n5️⃣ Launch & training\n6️⃣ Post-launch support', 'process,workflow,steps,how,method', 2, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(17, 'Timeline', 'Do you offer rush delivery?', 'Yes, rush delivery is available for urgent projects at 30-50% additional cost. Contact us to discuss your deadline!', 'urgent,rush,fast,quick,emergency', 3, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(18, 'Digital Marketing', 'What digital marketing services do you provide?', 'We offer complete digital marketing solutions:\n• SEO (Search Engine Optimization)\n• Social Media Marketing\n• Email Marketing\n• Content Marketing\n• Lead Generation\n• Brand Management\n• Graphic Design & Video Editing', 'marketing,seo,social media,digital', 1, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(19, 'Digital Marketing', 'How much does SEO cost?', 'SEO packages start from ₹8,999/month for local SEO and ₹15,999/month for national campaigns. Custom enterprise plans are also available.', 'seo,search,google,ranking,price', 2, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(20, 'Digital Marketing', 'Do you manage social media accounts?', 'Yes! We handle complete social media management including content creation, posting, engagement, analytics, and paid advertising across all major platforms.', 'social media,instagram,facebook,management', 3, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(21, 'Payment', 'What payment methods do you accept?', 'We accept:\n💳 Bank Transfer (NEFT/RTGS/IMPS)\n💳 UPI Payments\n💳 Credit/Debit Cards\n💳 International payments via PayPal', 'payment,pay,method,how,accept', 1, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(22, 'Payment', 'What is the payment structure?', 'Typically:\n• 50% advance before project start\n• 30% after design approval\n• 20% on final delivery\n\nFlexible payment plans available for long-term projects!', 'payment plan,installment,advance,milestone', 2, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38'),
(23, 'Payment', 'Do you provide invoices?', 'Yes, we provide GST invoices for all transactions. International clients receive standard invoices.', 'invoice,bill,gst,receipt', 3, 1, '2026-01-31 02:04:38', '2026-01-31 02:04:38');

