INSERT INTO `field_info` (`id`, `field_key`, `field_name`, `description`, `status`, `created_at`, `updated_at`) VALUES
(1, 'development', 'Development Services', 'We build robust, scalable, and innovative digital solutions tailored to your business needs. From web applications to mobile apps, our development team creates products that drive growth and enhance user experience.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(2, 'web_application', 'Web Application Development', 'Custom web applications built with modern technologies for optimal performance, security, and scalability. Perfect for businesses looking to automate processes and improve efficiency.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(3, 'ecommerce', 'E-commerce Solutions', 'Complete e-commerce platforms with secure payment gateways, inventory management, and seamless shopping experiences. Built to increase conversions and grow your online business.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(4, 'website_development', 'Website Development', 'Professional, responsive websites designed to captivate your audience and drive results. SEO-optimized and mobile-friendly for maximum reach and engagement.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(5, 'mobile_application', 'Mobile App Development', 'Native and cross-platform mobile applications for iOS and Android. Engaging user experiences with powerful features to connect with customers on-the-go.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(6, 'uiux', 'UI/UX Design', 'Intuitive and beautiful user interfaces that create memorable digital experiences. User-centric design approach that combines aesthetics with functionality.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(7, 'digital_marketing', 'Digital Marketing', 'Comprehensive digital marketing services to boost your online presence and drive targeted traffic. From SEO to social media, we help you reach and engage your ideal customers.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(8, 'seo', 'SEO Services', 'Search engine optimization strategies that improve your website visibility and organic rankings. Data-driven approach to increase traffic and conversions.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(9, 'lead_generation', 'Lead Generation', 'Targeted lead generation campaigns that deliver qualified prospects to your business. Multi-channel strategies to fill your sales pipeline consistently.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(10, 'email_marketing', 'Email Marketing', 'Strategic email campaigns that nurture relationships and drive conversions. Personalized messaging with automation to engage your audience effectively.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(11, 'brand_management', 'Brand Management', 'Build and maintain a strong brand identity across all digital channels. Consistent messaging and visual identity that resonates with your target audience.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(12, 'graphic_design', 'Graphic Design', 'Creative graphic design services for logos, marketing materials, social media graphics, and more. Eye-catching designs that communicate your brand message effectively.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(13, 'video_editing', 'Video Editing', 'Professional video editing and production services for marketing, social media, and corporate communications. Engaging visual content that tells your story.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23'),
(14, 'social_media', 'Social Media Marketing', 'Complete social media management including content creation, posting, engagement, and advertising. Build community and drive results across all major platforms.', 1, '2026-02-01 05:26:23', '2026-02-01 05:26:23');

