INSERT INTO `portfolio` (`id`, `title`, `type`, `subtype`, `clientname`, `category`, `keywords`, `authorname`, `publishdate`, `coverimage`, `description`, `isactive`, `createddate`, `updateddate`) VALUES
('0020fb38-728a-4ce7-b96a-6209de54cddd', 'Sports Branding & Digital Campaigns for Pruthvi Panthers', 'Marketing', 'Social Media', 'Pruthvi Panthers', 'Sports', NULL, 'KERYAR', '2025-08-05', '/images/keryar/portfolio/e9b00076-ee33-4f6d-94cb.jpg', '<p><strong>Pruthvi Panthers</strong> is a dynamic cricket team representing Baroda in the BPL 2025. Known for their fierce spirit and teamwork, the Panthers embody the energy and excitement of modern cricket.</p><p>Our creative team developed a bold and sporty digital identity — from match-day graphics and player highlights to fan engagement content and promotional campaigns. Every visual was crafted to reflect their passion, pride, and performance on the field.</p><p>The project aimed to create a strong emotional connection between the team and their fans, transforming Pruthvi Panthers into a powerful sports brand both on and off the pitch.</p>', 1, '2025-10-10 07:04:07', '2025-10-10 12:16:13'),
('06c9562b-0921-479f-92b1-1debed26e9d9', 'Empowering Global Education Aspirations', 'Marketing', 'Social Media', 'Skytech', 'Education', NULL, 'KERYAR', '2023-04-11', '/images/keryar/portfolio/16f7dd38-cab2-46eb-8ba4.jpg', '<p>Our team developed and managed SkyTech Overseas\' digital presence, focusing on creating a cohesive and appealing online identity. Through vibrant visuals, engaging content, and strategic campaigns, we enhanced the brand\'s connection with its audience.</p><p>Key initiatives included:</p><ul><li><strong>Instagram Marketing:</strong> Regular updates featuring success stories, service highlights, and educational tips.</li><li><strong>Creative Design:</strong> Visually appealing graphics and photography that reflect the brand\'s dedication to quality and student success.</li><li><strong>Digital Campaigns:</strong> Targeted promotions and collaborations to increase brand visibility and customer engagement.</li><li><strong>Community Engagement:</strong> Interactive posts and stories to foster a loyal and active online community.</li></ul><p><strong>Brand Outcome:</strong><br>Our efforts contributed to SkyTech Overseas\' growth as a trusted destination for study abroad guidance, with an online presence that mirrors its dedication to excellence and student success. Each post and campaign reinforced the brand\'s commitment to delivering exceptional educational experiences.</p>', 1, '2025-10-11 06:50:11', '2025-10-16 12:58:33'),
('0a6567dd-640b-4126-8245-4eeb9939bef2', 'Digital Branding & Social Media Strategy for The Pooja Electronics', 'Marketing', 'Social Media', 'The Pooja Electronics', 'Electronics', NULL, 'Keryar', '2025-10-07', '/images/keryar/portfolio/a791deec-0662-4663-b4fa.jpg', '<p><strong>The Pooja Electronics</strong> is your one-stop shop for premium electronic accessories — from chargers, cables, adapters, remotes, to smart home gadgets and more. <a href=\"https://www.instagram.com/thepoojaelectronics/?hl=en&amp;utm_source=chatgpt.com\">Instagram</a></p><p>For this client, we developed a brand-aligned social media presence and visual content strategy to showcase their product range, build customer trust, and drive online engagement. Our deliverables included:</p><ul><li>High visual graphics for product highlights (adapters, cables, remotes)</li><li>Informative posts about product features and usage</li><li>Consistent branding — tone, colors, style — across the feed</li><li>Content for promotions, launches, and offers</li></ul><p>The aim was to help The Pooja Electronics stand out in a competitive electronics accessory market, by combining clarity, aesthetic appeal, and brand consistency.</p>', 1, '2025-10-09 13:29:46', NULL),
('0b541bd2-cc33-4bb8-8132-ce544822d337', 'Ventura – Classifieds & Marketplace Mobile App', 'Development', 'Mobile App', 'Ventura', 'AutoMobile', 'marketplace app design, classifieds mobile app, buy sell app, ecommerce app ui, shopping app design, product listing app, modern ui ux design, mobile marketplace platform, product filter app, online store app design', 'KERYAR', '2024-12-10', '/images/keryar/portfolio/ec22c514-511e-45a9-8709-863885df75c0.jpg', '<p>Ventura is a modern and intuitive <strong>classifieds marketplace mobile app</strong> that connects buyers and sellers in one simple platform. Designed for both casual users and small businesses, the app offers a seamless way to list, search, and manage products across multiple categories—from electronics and vehicles to property and services.</p><p><strong>Design Approach:</strong><br>The goal was to create a bright, clean interface that feels both professional and easy to use. We chose a strong blue accent color to build brand trust and visual consistency across screens. The layout is designed for clarity—users can instantly find categories, browse trending items, or refine searches using smart filters.</p><p>Every component, from the home page to detailed search filters, is carefully structured to reduce cognitive load. The visual hierarchy makes it easy to navigate between sections like “Vehicles,” “Property,” “Fashion,” and “Jobs” while keeping the user experience consistent.</p><p><strong>Development Details:</strong><br>The app design supports real-time product listings, search filtering by price, condition, and brand, and seller profile management. A user-friendly posting flow lets sellers upload photos, add details, and manage ads effortlessly. The UI design is optimized for both Android and iOS devices.</p><p><strong>Highlights:</strong></p><ul><li>Clean and bright interface with strong brand color accents</li><li>Categorized listings for quick discovery</li><li>Advanced filtering options (price, brand, seller type, condition)</li><li>Verified and premium listing indicators for credibility</li><li>Profile management for buyers and sellers</li><li>Smooth navigation and mobile-optimized design</li></ul><p><strong>Outcome:</strong><br>Ventura delivers a powerful, intuitive marketplace experience that makes buying and selling online effortless. The sleek design, fast navigation, and clear structure give users confidence — whether they’re searching for a laptop, selling a vehicle, or posting a new listing.</p>', 1, '2025-10-31 10:04:30', NULL),
('0ce1592e-67b9-4a9f-a1e5-9400d9e686c7', 'Infant Branding & Digital Storytelling', 'Marketing', 'Social Media', 'Reevas Baby', 'Fashion', NULL, 'KERYAR', '2025-02-03', '/images/keryar/portfolio/5e33c2ce-94cd-4fe5-bfea.jpg', '<p>Reevas Baby captures the joy, innocence, and daily moments of early childhood. Our creative approach centered on crafting a warm, tender, and visually consistent digital identity — from soft pastel palettes and gentle typography to curated photo styles and content sequences. We conceptualized content that tells personal stories, highlights baby milestones, and connects emotionally with parents and followers.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Visual Identity:</strong> Developing a gentle and approachable visual style (colors, fonts, icons) suited for baby / parenting audiences.</li><li><strong>Photography &amp; Styling:</strong> Curating photo and video content of baby moments, milestones, props, and soft textures.</li><li><strong>Content Calendar &amp; Storytelling:</strong> Planning posts and stories around growth, events (birthdays, milestones), and daily life.</li><li><strong>Social Media Campaigns:</strong> Creating engagement posts, baby product features, parenting tips, and community interactions.</li><li><strong>Reels &amp; Video Content:</strong> Producing short videos (reels) showcasing baby’s day, milestones, and cute moments with trending audio.</li></ul><p><strong>Outcome:</strong><br>The campaign fosters a strong emotional bond with followers, enhances the Reevas Baby brand’s trust and appeal to parents, and creates a beautiful, recognizable feed that celebrates life’s earliest days.</p>', 1, '2025-10-10 09:46:34', '2025-10-10 11:41:03'),
('134ab566-ee20-4899-96a4-2dc5042294e0', 'Food Delivery Mobile App', 'Development', 'Mobile App', 'Foodio', 'Food', 'food delivery app, mobile ui design, ux design, food ordering, restaurant app, cart system, modern ui, app design portfolio', 'KERYAR', '2024-06-04', '/images/keryar/portfolio/6f594cf7-8226-437c-b3af-c6ea7060d758.jpg', '<p>Foodio is a fresh and modern mobile application designed to make ordering food fast, simple, and enjoyable. The app combines a clean interface with vibrant visuals, offering users a smooth browsing and checkout experience.</p><p><strong>Design Approach:</strong><br>The design focuses on clarity and accessibility. We used bright green accent tones to create an energetic, appetizing feel and guide user actions like signing in, browsing menus, and placing orders. Each screen — from sign-in to cart checkout — is crafted to minimize friction and enhance usability.</p><p>Category icons and product cards are designed with rounded edges and soft shadows for a friendly look, while key details like distance, delivery time, and ratings are highlighted for quick decision-making.</p><p><strong>Development Details:</strong><br>The app structure supports multiple restaurant listings, product categories (Drinks, Food, Cake), and an integrated shopping cart. Users can apply discount codes, track delivery costs, and adjust quantities easily. The experience is responsive across devices and built with scalable design components for easy expansion.</p><p><strong>Highlights:</strong></p><ul><li>Clean, intuitive UI with consistent layout and iconography</li><li>Smooth onboarding with quick sign-in and social login options</li><li>Clear product hierarchy with price, rating, and restaurant info</li><li>Interactive cart system with real-time total and discount options</li><li>Balanced visual design for usability and brand identity</li></ul><p><strong>Outcome:</strong><br>The final design delivers a user-friendly mobile experience that blends functionality with freshness. Foodio helps users discover nearby restaurants, explore menus, and order their favorite meals effortlessly — all wrapped in a visually modern, easy-to-navigate interface.</p>', 1, '2025-10-31 09:43:07', '2025-10-31 10:19:28'),
('13a9420d-1332-45a9-8fdd-c3e3b28127e1', 'Job Platform Branding & Digital Strategy', 'Marketing', 'Social Media', 'QuickOB', 'Technology', NULL, 'KERYAR', '2024-10-30', '/images/keryar/portfolio/6d5b9910-4749-4d2f-916f.jpg', '<p>QuickOB connects talent with opportunities and builds digital tools for careers and hiring. The goal is to establish a professional, trustworthy, and engaging brand in the HR tech space.</p><h3>Scope of Work:</h3><ul><li>Brand Identity (logo, color palettes, typography)</li><li>Website / UI / UX design for job search and resume tools</li><li>Marketing &amp; Social Media Campaigns (launch, promotions, content)</li><li>Email Marketing &amp; Drip Campaigns for users &amp; employers</li><li>Content Strategy &amp; SEO (job-related keywords, career articles)</li><li>User Engagement &amp; Onboarding Flows</li></ul><h3>Outcome:</h3><p>Enhanced brand perception, increased user registrations, better engagement metrics, improved search rankings for terms like <i>“online resume builder”</i>, <i>“job portal USA”</i>, etc.</p>', 1, '2025-10-10 11:18:55', '2025-10-10 11:50:48'),
('141efdd2-1ff7-4a77-bc26-64e3d012c31f', 'Miro – Business Collaboration & Productivity Website', 'Development', 'Website', 'Miro', 'Industries', 'business collaboration website, saas web design, team productivity platform, ui ux design, b2b web development, modern corporate website, enterprise web design, web app interface, remote work platform design, software company website', 'KERYAR', '2023-10-11', '/images/keryar/portfolio/0b270284-0bce-46bf-83ed-a6550e0d8fe3.jpg', '<p><strong>Project Overview:</strong><br>Miro is a dynamic <strong>business collaboration platform</strong> designed to connect teams, streamline workflows, and enhance productivity. The website reflects a modern SaaS identity — bold, clean, and focused on empowering organizations to brainstorm, plan, and execute together, no matter where they work.</p><p><strong>Design Approach:</strong><br>The design emphasizes clarity and collaboration. We used a minimal color palette of white, deep navy, and accents of yellow to create contrast and guide attention. Every section is structured around usability — from clear call-to-actions to concise messaging and iconography that supports readability.</p><p>Large typography and visual hierarchy make key sections like <i>“Collaborate without constraints”</i> and <i>“Built for the way you work”</i> stand out. Illustrations and product mockups help users visualize real use cases, while interactive elements keep engagement high.</p><p><strong>Development Details:</strong><br>The website is built with a responsive layout that adjusts seamlessly across devices. The structure includes multiple feature-focused sections such as integrations, testimonials, and trust metrics. Key backend functionality supports scalability, fast load times, and SEO optimization for SaaS keywords.</p><p><strong>Highlights:</strong></p><ul><li>Clean, high-contrast design with strong brand presence</li><li>Organized layout focusing on features and benefits</li><li>Integration-focused design showcasing 100+ supported tools</li><li>Optimized for B2B SaaS lead generation and conversions</li><li>Engaging animations and CTA-driven layout</li><li>Responsive and mobile-optimized user experience</li></ul><p><strong>Outcome:</strong><br>The final website successfully conveys Miro’s brand as a leader in collaborative software. It offers a seamless user journey from discovery to signup, helping visitors quickly understand the product’s value. The result is a modern, scalable website that enhances credibility, boosts engagement, and strengthens Miro’s position in the SaaS market.</p>', 1, '2025-10-31 10:27:33', NULL),
('14484bad-1e7f-4db4-b8f3-37e1313afa48', 'Food Branding & Digital Storytelling', 'Marketing', 'Social Media', 'Khana Khazana ', 'Food', NULL, 'KERYAR', '2024-09-16', '/images/keryar/portfolio/1526befc-c6a6-482d-8f0c.jpg', '<p>Khana Khazana &nbsp;is known for its diverse menu, rich flavors, and welcoming ambiance. Our creative team collaborated to craft a cohesive digital identity — from mouthwatering food photography and menu visuals to social media campaigns and customer engagement content. Every design element aimed to evoke appetite, trust, and the brand’s unique flavor personality. The goal was to elevate their presence online, draw in food lovers, and reflect the culinary excellence Khana Khazana 1760 delivers.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Defining a visual style (logo, color palette, typography) that aligns with the brand’s culinary ethos.</li><li><strong>Food Photography &amp; Styling:</strong> Capturing drool-worthy images of dishes, plating compositions, and behind-the-scenes.</li><li><strong>Menu and Visual Assets:</strong> Designing menus (print &amp; digital), banners, signage, and in-store visuals.</li><li><strong>Digital Campaigns:</strong> Creating social media content — promos, special dishes, stories, reels, and event announcements.</li><li><strong>Customer Engagement:</strong> Templates for reviews, polls, user-generated content, and loyalty campaigns.</li></ul><p><strong>Outcome:</strong><br>The revamped digital branding strengthened Khana Khazana appeal among foodies, increased social media engagement, and enhanced footfall and orders through visually compelling and consistent content.</p>', 1, '2025-10-10 09:43:40', NULL),
('188c6fe9-09e6-47d4-a830-1f391214d8dd', 'Sports Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Capetown Samp Army', 'Sports', NULL, 'KERYAR', '2025-10-12', '/images/keryar/portfolio/1d03efdb-088b-4c1b-8daf.jpg', '<p>Capetown Samp Army represents the bold and fearless spirit of modern cricket. Competing in the fast-paced <strong>60-ball format</strong>, the team brings together passion, power, and entertainment. Our creative team developed a dynamic sports branding identity — from match-day graphics and player highlight visuals to digital fan engagement and promotional campaigns. Every element was designed to capture the intensity of the game and the pride of the Capetowns Army supporters.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Team Branding:</strong> Crafted a strong and sporty visual identity to represent the team’s energy and values.</li><li><strong>Digital Campaigns:</strong> Designed engaging content for social media — match updates, highlights, and announcements.</li><li><strong>Player Highlights:</strong> Created spotlight graphics and reels for key players and memorable performances.</li><li><strong>Fan Engagement:</strong> Built interactive posts and hype content to energize the fan community.</li><li><strong>Event Promotions:</strong> Developed promotional creatives for matches, ticket sales, and collaborations with the league.</li></ul><p><strong>Outcome:</strong><br>The campaign successfully positioned Capetowns Army as one of the most vibrant and recognizable teams in the <strong>Zim Afro T10 League</strong>, strengthening their connection with cricket fans across Africa and beyond.</p>', 1, '2025-10-10 09:49:51', '2025-10-10 11:56:24'),
('195368fa-5299-48cc-87c2-fcf0153caa04', 'Brand Identity & Digital Campaigns for 9 to 69 Café', 'Marketing', 'Social Media', '9 TO  69 Cafe', 'Food', NULL, 'KERYAR', '2025-08-05', '/images/keryar/portfolio/5261faeb-76f4-4387-99fc.jpg', '<p>9 to 69 Café is a vibrant and budget-friendly café chain with multiple locations in Vadodara, including Nizampura, Tarsali, and Akota. <a href=\"https://www.zomato.com/vadodara/9-to-69-cafe-nizampura?utm_source=chatgpt.com\">Zomato+2Zomato+2</a> Renowned for its innovative pricing model, the café offers a diverse menu ranging from sandwiches and burgers to waffles and momos, all priced between ₹9 and ₹69. <a href=\"https://www.zomato.com/vadodara/9-to-69-cafe-nizampura?utm_source=chatgpt.com\">Zomato</a></p><p>Our creative team developed a dynamic and engaging digital identity for 9 to 69 Café, encompassing social media graphics, promotional campaigns, and menu highlights. Each visual element was crafted to reflect the café\'s youthful energy, affordability, and commitment to quality.</p><p>The project aimed to strengthen the café\'s brand presence, attract a diverse clientele, and create a cohesive brand image that resonates with food enthusiasts seeking delicious meals without breaking the bank.</p>', 1, '2025-10-10 07:20:57', NULL),
('1a215453-446f-4099-9f18-2de6f3f38628', 'Abu Dhabi T10 League Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Morrisville Samp Army', 'Sports', NULL, 'KERYAR', '2024-06-07', '/images/keryar/portfolio/28966aa8-1cd2-49bf-9ca8.jpg', '<p>Morrisville Samp Army plays in the high-octane Abu Dhabi T10 League, featuring 10 overs per side matches that demand power, precision, and flair. The team boasts star players like <strong>Faf du Plessis</strong>, <strong>Jason Holder</strong>, and <strong>Moeen Ali</strong>, who bring international experience and huge fan draw. Our creative strategy captured the team’s intensity and global appeal, designing visuals and campaigns that resonate with both hardcore cricket fans and broader audiences.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity &amp; Visual Style:</strong> Developed a vibrant and energetic design language — bold colors, strong typography, and dynamic player imagery — that emphasizes speed, strength, and international standard.</li><li><strong>Match Highlights &amp; Player Spotlights:</strong> Created graphics, reels, and content featuring key performances by Faf du Plessis, Jason Holder, Moeen Ali, and other top figures.</li><li><strong>Digital &amp; Social Media Campaigns:</strong> Engaging posts, teasers, match-day promotions, and interactive content (polls, countdowns) to build hype before each match.</li><li><strong>Email Marketing Campaigns:</strong> Newsletters targeting fans and subscribers, including match previews, player stats, exclusive interviews, and ticket or merchandise promotions.</li><li><strong>SEO &amp; Content Strategy:</strong> Blog posts, match reports, player profiles, and SEO-optimized content to improve online visibility for “Abu Dhabi T10”, “Morrisville Samp Army”, “Faf du Plessis batting highlights”, etc.</li></ul><p><strong>Outcome:</strong><br>The campaign enhanced Morrisville Samp Army’s brand presence in the Abu Dhabi T10 League and beyond, boosted fan engagement with content centered around marquee players, and improved digital traction. Search traffic for keywords like “Morrisville Samp Army Abu Dhabi T10” and “Faf du Plessis Abu Dhabi performance” increased, reinforcing the team’s standing as a top-tier T10 franchise.</p>', 1, '2025-10-10 11:13:45', '2025-10-10 11:50:59'),
('1faac2a6-f7ff-47b0-ba1d-3c7614bde7da', 'Culinary Heritage Meets Modern Dining', 'Marketing', 'Social Media', 'The Swan INN', 'Food', NULL, 'KERYAR', '2025-10-10', '/images/keryar/portfolio/55e48d26-5bc9-448e-b185.jpg', '<p>The food menu centers on <strong>expertly crafted gourmet burgers</strong> and <strong>house-made desserts</strong>, each dish designed to deliver taste and quality. Alongside meals, The Swan Inn operates a gourmet retail section, offering curated items for guests to enjoy beyond their visit. The ambiance is warm and atmospheric, blending heritage architecture with contemporary touches — creating a space where conversations linger, flavors stay memorable, and every visit feels special.</p><p>Anchored in its historical locale, The Swan Inn Bar &amp; Kitchen balances culinary innovation with a respect for tradition, delivering not just food, but a full dining story.</p>', 1, '2025-10-10 13:21:10', NULL),
('204baaee-0b31-433c-bd79-de70202bd7e1', 'Community-Centric Adult Day Services', 'Marketing', 'Social Media', 'Bucks', 'Healthcare', NULL, 'KERYAR', '2024-11-01', '/images/keryar/portfolio/814fca3a-983e-4f94-9feb.jpg', '<p>At Bensalem Adult Day Care, every day is thoughtfully planned to promote well-being, independence, and joy. The facility offers a wide range of <strong>personalized care programs</strong> that focus on physical, emotional, and mental wellness. From daily health monitoring and medication reminders to fitness sessions, cognitive games, and creative workshops — each activity is designed to keep participants healthy, engaged, and happy.</p><p>The center provides <strong>fresh, nutritious meals</strong> prepared with dietary needs in mind, ensuring every guest enjoys both taste and nourishment. A team of compassionate caregivers and healthcare professionals work closely with families to understand each participant’s unique needs, building individualized care plans that balance attention and autonomy.</p><p>Beyond care, the environment at Bensalem Adult Day Care fosters <strong>social connection and community</strong>. Group activities, themed events, and social gatherings encourage friendships, laughter, and meaningful engagement — helping to reduce isolation and enhance quality of life.</p><p>With modern facilities, a warm atmosphere, and a dedicated staff, Bensalem Adult Day Care is not just a service — it’s a <strong>place of trust, love, and dignity</strong> where families can feel confident that their loved ones are receiving the best possible care and companionship.</p><p>✨ <i>Empowering adults to live fully, connect deeply, and age gracefully — one day at a time.</i></p>', 1, '2025-10-10 11:23:22', '2025-10-10 11:49:34'),
('2711f3f6-8ab2-421b-8c32-ec2e31cea2bb', 'High-Octane Cricket & Digital Branding', 'Marketing', 'Social Media', 'Grand Cayman Falcons', 'Sports', NULL, 'KERYAR', '2025-08-01', '/images/keryar/portfolio/35439ed9-f7cd-4d42-a1cf.jpg', '<p>In the electrifying context of MAX60 Caribbean, the Falcons needed a brand identity and digital campaign that reflected speed, skill, and Caribbean flair. From matchday graphics and player spotlight content to fan engagement and storytelling, our creative effort aimed to transform the team’s performance into a compelling, visual narrative. The branding was designed to resonate both with local supporters on Grand Cayman and global cricket fans tuning in. <a href=\"https://www.caymaniantimes.ky/documents/2024-07-24-19-06-18-CT1005WEB.pdf?utm_source=chatgpt.com\">Cricket Addictor+3caymaniantimes.ky+3ESPN.com+3</a></p><p><strong>Scope of Work:</strong></p><ul><li><strong>Team Branding:</strong> Creating a visual identity (logo, color scheme, typography) that communicates power, unity, and sportiness.</li><li><strong>Matchday &amp; Highlight Graphics:</strong> Designing assets for live match updates, scorecards, key moments, and standout performances.</li><li><strong>Player-Focused Content:</strong> Profiles, reels, and spotlight features on individual players to build fan connection.</li><li><strong>Fan Engagement:</strong> Interactive content — polls, behind-the-scenes, match predictions — to bring the community into the action.</li><li><strong>Promotional Campaigns:</strong> Social media campaigns for upcoming fixtures, ticket-ing (if applicable), and sponsorship visibility.</li></ul><p><strong>Outcome:</strong><br>The campaign strengthened the Grand Cayman Falcons’ visibility in the MAX60 League, improved fan engagement, and helped build a more cohesive and recognizable brand identity in the fast-paced 60-ball format. The visuals and content helped amplify match excitement and celebrate cricketing excellence.</p>', 1, '2025-10-10 09:52:50', '2025-10-10 11:56:10'),
('3267b51e-3060-4820-9728-fd0170e67f6d', 'Digital Branding & Social Media Campaigns', 'Marketing', 'Social Media', 'Rangvastra', 'Fashion', NULL, 'KERYAR', '2023-06-06', '/images/keryar/portfolio/2fb950c4-c598-4a5e-a0af.jpg', '<p>Our team managed Rangvastra’s complete digital presence and branding — from social media identity to creative campaigns and content design. We crafted a strong, engaging look across Instagram through colorful visuals, dynamic reels, and captivating photography.</p><p>We focused on:</p><ul><li><strong>Instagram Marketing:</strong> Showcasing product highlights, festival collections, style tips, and engaging reels.</li><li><strong>Creative Design:</strong> Aesthetic layouts, vibrant visuals, and catchy copy to reflect elegance, tradition, and modernity.</li><li><strong>Digital Campaigns:</strong> Targeted promotions, festive launches, and influencer collaborations to boost reach.</li><li><strong>Community Building:</strong> Interactive stories, polls, and updates to engage followers and build loyalty.</li></ul><p><strong>Brand Outcome:</strong><br>Through a strategic digital approach, Rangvastra’s online presence became a visually appealing, trend-conscious ethnic wear brand. Each post reflects the brand’s passion for style, tradition, and celebrating life’s special moments.</p>', 1, '2025-10-11 06:37:10', '2025-10-16 12:58:16'),
('337beccb-0108-49a0-8265-229ab725f787', 'FitBuddy – Fitness & Workout Tracking App ', 'Development', 'Mobile App', 'FitBuddy', 'Healthcare', 'fitness app, workout tracker app, gym app design, mobile ui design, health and fitness app, personal trainer app, exercise tracking app, yoga app ui, fitness mobile app ui ux, wellness app design', 'KERYAR', '2024-09-05', '/images/keryar/portfolio/0b9d22a3-2a62-4fab-a15a-5e07fe3f1341.jpg', '<p><strong>Project Overview:</strong><br>FitBuddy is a sleek and modern mobile application designed to help users manage their workouts, track fitness progress, and stay motivated to reach their health goals. The app delivers a clean, energetic experience that makes tracking daily activity and discovering workout plans effortless.</p><p><strong>Design Approach:</strong><br>The main goal was to create a user-friendly, motivating interface that feels fresh and active. The app uses bright, clean colors with plenty of white space and soft gradients to promote focus and positivity. The onboarding screen sets an encouraging tone, leading into a personalized dashboard with “Today’s Activity,” recommended classes, and progress tracking.</p><p>Each section—from yoga sessions to cardio tracking—is organized with simple navigation and clear visual hierarchy. Smooth animations, illustrated exercise cards, and intuitive charts keep the experience lively yet easy to follow.</p><p><strong>Development Details:</strong><br>FitBuddy’s design supports class recommendations, real-time progress tracking, and video-based workout sessions. The UI is optimized for both Android and iOS platforms, ensuring consistent performance and an intuitive experience across devices.</p><p><strong>Highlights:</strong></p><ul><li>Clean, modern interface with a motivating tone</li><li>Dashboard to view daily activities and calories burned</li><li>Video-based exercise guidance</li><li>Class recommendations (yoga, warm-ups, strength, cardio)</li><li>Integrated statistics tracking for workouts and progress</li><li>Designed for scalability and personalization</li></ul><p><strong>Outcome:</strong><br>The final app offers an energetic, motivating, and easy-to-use interface that helps users stay active and on track with their fitness goals. FitBuddy combines smart UX with a clean visual style, making exercise tracking not just simple — but genuinely enjoyable.</p>', 1, '2025-10-31 09:58:55', '2025-10-31 10:18:46'),
('36568166-9b09-483c-8785-ce51142fb8a6', 'South Asian Cuisine Branding & Digital Presence', 'Marketing', 'Social Media', 'Desi Thekka', 'Food', NULL, 'KERYAR', '2025-03-06', '/images/keryar/portfolio/964bae5f-e8c9-4cd5-8045.jpg', '<p>Desi Thekka Watford seeks to bring the vibrant, rich tastes of South Asia to the local community in Watford. Our work focused on translating delicious food into visual appeal — building a brand identity and social media presence that highlights authenticity, flavor, and cultural warmth. The objective was to make Desi Thekka a go-to destination for people craving genuine desi cuisine, while differentiating it in a competitive market.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Creating a logo, color scheme, typography, and motifs that reflect South Asian heritage and modern dining vibes.</li><li><strong>Food Photography &amp; Styling:</strong> Capturing mouthwatering dishes with vibrant colors, textures, and compositions to attract attention and appetite.</li><li><strong>Menu Visuals &amp; Design:</strong> Designing visual layouts for menus (digital &amp; print), showcasing signature dishes, combo offers, and specials.</li><li><strong>Digital &amp; Social Campaigns:</strong> Posts, stories, reels promoting special dishes, offers, cultural festivals, and behind-the-scenes content.</li><li><strong>Customer Engagement:</strong> Developing interactive posts, testimonial features, comments, polls (“which dish next?”), and loyalty content.</li></ul><p><strong>Outcome:</strong><br>The branding and digital campaign helped Desi Thekka Watford establish a distinct visual voice, increased online engagement, and turned casual viewers into diners by making the food look irresistible. The consistent visuals and storytelling built a stronger brand identity in the local food scene.</p>', 1, '2025-10-10 11:33:24', NULL),
('396dd16b-5033-4ee1-a636-f808d10b256b', 'Brand Identity & Creative Content for Gurukrupa Jewellers, Petlad', 'Marketing', 'Social Media', 'Gurukrupa Jewellers', 'Jewellers', NULL, 'Keryar', '2025-09-17', '/images/keryar/portfolio/d03c5306-59cf-458c-bc63.jpg', '<p>Gurukrupa Jewellers, located in Petlad, Gujarat, is a distinguished jewellery house known for offering <strong>gold, silver, diamond, and platinum</strong> pieces with an emphasis on purity, craftsmanship, and customer trust.</p><p>With a strong presence on Instagram (1,273+ posts, over 11K followers) <a href=\"https://www.instagram.com/gurukrupajewellerspetlad/reels/\">Instagram</a>, their brand voice is built around elegance, tradition, and timeless designs.</p><p>For this client, our team delivered:</p><ul><li>A cohesive visual identity and aesthetic for social media</li><li>Engaging content in line with their brand values — highlighting craftsmanship, purity, and elegance</li><li>Posts that balance promotional content and storytelling — linking jewellery pieces to emotions, occasions, and heritage</li><li>Consistent branding across all visuals, ensuring the feed looks unified and reflects the benchmarks of a premium jewellery brand</li></ul><p>The result is a polished, trust-evoking visual presence that helps Gurukrupa Jewellers connect with their audience and reflect the luxury and authenticity they stand for.</p>', 1, '2025-10-09 13:15:54', '2025-10-09 13:39:43'),
('41feb16c-74b3-411b-9734-2b6d13011b31', 'Catering & Culinary Branding', 'Marketing', 'Social Media', 'Radhika Caters', 'Service Industries', NULL, 'KERYAR', '2023-08-07', '/images/keryar/portfolio/31944fe8-61fc-4d03-a858.jpg', '<p>Radhika Caters crafts menus that balance traditional flavors with modern presentation. From appetizers to desserts, each course is thoughtfully designed for taste, visual appeal, and guest delight. The brand emphasizes fresh ingredients, custom themes, dietary flexibility (vegetarian, vegan, regional cuisines), and meticulous execution.</p><p>Visually, the branding is refined and appetizing — using rich colors, elegant typography, and high-quality food photography to reflect the prestige and excellence of the service. Social media content includes event showcases, behind-the-scenes kitchen stories, client testimonials, and menu highlights to build trust and appetite.</p><p>Radhika Caters stands out for its <strong>reliability, creativity, and personalized approach</strong> — making sure every event is memorable through exceptional food, seamless service, and impeccable presentation.</p>', 1, '2025-10-10 13:33:43', NULL),
('47e6bf3f-8bf9-4820-bd4f-7964db7f9c5f', 'Food Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Jalaram Sandwich', 'Food', NULL, 'KERYAR', '2025-10-10', '/images/keryar/portfolio/3c7f1cb9-4254-475d-9b7a.jpg', '<p>With the growing demand for convenience without compromising taste, Jalaram Sandwich introduced a new line of frozen snacks. Our creative team crafted a fresh and appealing digital identity — from packaging design and product photography to promotional campaigns and social media content. Every visual captured the brand’s essence of <strong>taste, trust, and tradition</strong>, reimagined for the modern kitchen. The goal was to position Jalaram Sandwich as a reliable frozen food brand bringing authentic street flavors right to your freezer.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Designed packaging and branding that reflects freshness, flavor, and authenticity.</li><li><strong>Product Launch Campaign:</strong> Created visuals and short videos to introduce frozen food items online.</li><li><strong>Social Media Content:</strong> Developed engaging posts, recipes, and reels highlighting quick-prep meals.</li><li><strong>Photography &amp; Design:</strong> Shot vibrant, appetizing product visuals for use across platforms.</li><li><strong>Retail Promotion:</strong> Designed in-store posters and digital creatives for supermarkets and distributors.</li></ul><p><strong>Outcome:</strong><br>The campaign successfully launched Jalaram Sandwich’s frozen food line, boosted brand visibility across Gujarat, and positioned it as a go-to option for quick, flavorful meals at home.</p>', 1, '2025-10-10 09:38:59', NULL),
('48b18df7-abdd-4bd5-9e0c-c25d230b3bd8', 'Heritage & Cultural Branding & Digital Presence', 'Marketing', 'Social Media', 'Mount Heritage\\', 'Resort', NULL, 'KERYAR', '2024-01-02', '/images/keryar/portfolio/9f4111f1-3152-4b7d-ad7f.jpg', '<p>Our creative team developed a <strong>refined digital identity</strong> for Mount Heritage, highlighting its luxurious stay experience, serene environment, and top-notch hospitality. From visual storytelling to social media campaigns, every element was crafted to reflect relaxation, warmth, and authenticity.</p><p>We focused on showcasing the property’s unique atmosphere — cozy interiors, breathtaking views, and the personalized care that defines the Mount Heritage experience. The branding emphasizes <strong>heritage-inspired elegance</strong>, creating an emotional connection with travelers seeking peace, comfort, and memorable stays.</p><p><strong>Brand Essence:</strong><br>Mount Heritage stands for <strong>comfort, culture, and calm</strong> — a retreat where tradition meets modern hospitality to offer guests a truly enriching experience.</p>', 1, '2025-10-10 13:16:57', NULL),
('493a240d-261f-4cb7-916b-02dd58d7a83c', 'Study Abroad Consulting & Global Education Support', 'Marketing', 'Social Media', 'EVS', 'Education', NULL, 'keryar', '2024-08-07', '/images/keryar/portfolio/6b1a9a80-f8ff-476e-831e.jpg', '<p>EVS offers end-to-end services for international education: selecting best-fit universities, application document assistance (statement of purpose, transcripts, etc.), visa guidance, and pre-departure preparation. They refine student profiles, help with standardized test prep (IELTS, TOEFL etc.), and ensure every detail is covered — from admission requirements to after arrival support.</p><p>On the digital side, their marketing strategy includes strong content in social media (Instagram, Facebook) showcasing student success stories, university highlights, live Q&amp;A sessions, tips for visa interviews, and checklists for pre-departure. They build trust by sharing real client experiences, clarified processes, and transparent fee / timeline expectations.</p><p>Through this full spectrum service + strong storytelling + digital engagement, EVS positions itself not just as a consultant, but as a partner in a student’s global education journey — helping turn aspirations of studying abroad into clearly achievable reality.</p>', 1, '2025-10-10 13:24:41', NULL),
('4a8f6200-87c1-4d47-9086-e28ce5e619ee', 'Car Wash Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Mr.Sudz', 'Service Industries', NULL, 'KERYAR', '2025-05-09', '/images/keryar/portfolio/3cedd9e0-b64f-41fc-b91b.jpg', '<p>Mr. Sudz Express stands for speed, shine, and satisfaction. Our creative team developed a clean and vibrant digital identity that captures the essence of the brand — premium car care made quick and effortless. From social media visuals to promotional campaigns, every element was designed to reflect trust, efficiency, and attention to detail.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Crafted a sleek and modern logo, color scheme, and typography symbolizing freshness and quality.</li><li><strong>Social Media Campaigns:</strong> Designed digital content promoting car wash packages, detailing services, and customer offers.</li><li><strong>Photography &amp; Visuals:</strong> Captured high-quality shots of vehicles, equipment, and before-after transformations.</li><li><strong>Email Marketing:</strong> Developed promotional emails and loyalty campaigns to engage repeat customers and boost retention.</li><li><strong>Promotional Materials:</strong> Designed banners, posters, and flyers to support marketing efforts both online and onsite.</li></ul><p><strong>Outcome:</strong><br>The campaign successfully positioned Mr. Sudz Express as a premium yet approachable car wash brand. The visuals and content helped boost customer trust, attract new clients, and create a recognizable digital presence that stands out in the automotive care industry.</p>', 1, '2025-10-10 10:52:34', '2025-10-10 11:53:35'),
('4be55f27-6c40-4988-8234-41391e6a7327', 'Visual Branding & Social Media for Hummus Republic (Maryland)', 'Marketing', 'Social Media', 'Hummus Republic', 'Food', NULL, 'KERYAR', '2025-09-29', '/images/keryar/portfolio/03c4232a-719d-448d-85de.jpg', '<p><strong>Hummus Republic</strong> is a franchise focused on authentic Middle Eastern cuisine, especially its signature hummus bowls, fresh wraps, and Mediterranean flavors.</p><p>In our collaboration, we:</p><ul><li>Developed a clean, fresh visual identity highlighting natural ingredients and vibrant textures</li><li>Crafted content that emphasizes the brand’s culinary expertise and healthy eating appeal</li><li>Designed posts, graphics, and layouts to suit menu promotions, product highlights, and seasonal offers</li></ul><p>The goal was to refresh Hummus Republic’s digital presence to better reflect its culinary values, connect with health-conscious consumers, and showcase authentic flavor in every post.</p>', 1, '2025-10-10 07:01:31', NULL),
('4d395950-871a-41c0-a3dd-d2e53589cabb', 'Complete Digital Branding by Our Team', 'Marketing', 'Social Media', 'KERYAR', 'Service Industries', NULL, 'KERYAR', '2019-01-11', '/images/keryar/portfolio/c48ffcf2-afb2-45b2-9e87.jpg', '<p>Keryar is a modern fashion and lifestyle brand that redefines elegance with a contemporary touch. Our team handled their <strong>complete digital branding</strong>, crafting a cohesive online identity that reflects sophistication and individuality.</p><p>From logo and color palette development to social media visuals, campaign strategy, and content design — every element was tailored to capture Keryar’s premium yet approachable vibe. We focused on creating a visual language that speaks to trendsetters and style enthusiasts, ensuring brand consistency across all digital platforms.</p><p>The result is a clean, fashion-forward digital presence that positions Keryar as a <strong>refined and aspirational lifestyle brand</strong>, connecting deeply with its modern audience through design, storytelling, and creativity.</p>', 1, '2025-10-11 06:28:11', NULL),
('540945af-062d-49e7-bff0-f91c30d49379', 'Crito Creative Agency Website Design', 'Development', 'Website', 'Crito', 'Service Industries', 'creative agency, website design, UI/UX design, branding, marketing website, portfolio, business landing page', 'KERYAR', '2024-07-17', '/images/keryar/portfolio/e3ed80e5-e9b2-4fe8-99e9-c52dd6f6d7d5.jpg', '<p>Crito Creative Agency is a sleek, modern website designed to showcase the agency’s services, team, and creative approach. The goal was to build a digital experience that feels approachable yet professional — helping the brand connect with clients looking for design, development, and marketing expertise.</p><p><strong>Design Approach:</strong><br>We focused on clean layouts, soft color gradients, and human-centric visuals to make the site both friendly and credible. The hero section captures attention with a confident headline and expressive imagery, followed by clearly structured service cards and client showcases. Each section was crafted for easy navigation and readability, ensuring the visitor journey feels smooth and intuitive.</p><p><strong>Development Details:</strong><br>The website is fully responsive, built using modern front-end technologies. Interactive elements, subtle animations, and a structured grid system make the browsing experience engaging without overwhelming the user.</p><p><strong>Highlights:</strong></p><ul><li>Consistent brand tone and color palette across pages</li><li>Dedicated portfolio and testimonial sections to build trust</li><li>FAQ and contact forms integrated for better lead conversion</li><li>Optimized performance for both desktop and mobile</li></ul><p><strong>Outcome:</strong><br>The result is a visually balanced, high-performing agency website that reflects Crito’s mission — helping businesses unlock their creative and digital potential.</p>', 1, '2025-10-31 09:32:58', '2025-10-31 09:43:24'),
('574e6997-6c13-4f37-908d-ee09d48e07d8', 'Inwood – Modern Furniture eCommerce Website', 'Development', 'Website', 'Inwood', 'Interior', 'furniture website design, ecommerce web design, modern home decor website, furniture shop online, ui ux design, responsive ecommerce website, furniture store development, interior design web design, product catalog website, minimalist furniture website', 'KERYAR', '2024-06-03', '/images/keryar/portfolio/1b1fb4bd-9a29-4f63-9e91-d85cea681fd3.jpg', '<p>Inwood is a <strong>modern furniture eCommerce website</strong> designed to showcase high-quality home furnishings with a focus on elegance, simplicity, and seamless user experience. The design balances a minimalist layout with rich imagery, making it easy for customers to explore collections and shop effortlessly.</p><p><strong>Design Approach:</strong><br>The interface was crafted with calm tones, clean typography, and plenty of white space to give a sophisticated and airy look — mirroring the brand’s commitment to modern, natural design. The goal was to create an atmosphere of comfort and style while maintaining an intuitive shopping flow.</p><p>The homepage immediately highlights <i>exclusive deals</i> and <i>featured categories</i> like Living Room, Bedroom, and Kitchen, while the product sections use soft color palettes to make each item visually distinct. Icons, clean grids, and consistent spacing help the user journey feel smooth and pleasant.</p><p><strong>Development Details:</strong><br>Built with a responsive front-end design, the website performs seamlessly across all devices. It includes an optimized product catalog, smart filtering, cart integration, and customer testimonial sections to build trust. The backend supports easy product management and secure transactions.</p><p><strong>Highlights:</strong></p><ul><li>Clean, minimalist layout with elegant color tones</li><li>Responsive eCommerce design for mobile and desktop</li><li>Organized category structure for intuitive browsing</li><li>Product highlights with pricing and quick “Add to Cart” actions</li><li>Customer testimonials and newsletter integration</li><li>SEO-optimized and performance-focused build</li></ul><p><strong>Outcome:</strong><br>The Inwood website successfully represents the brand’s modern aesthetic and enhances the customer shopping experience. With its minimal design, organized navigation, and strong visual storytelling, it offers a refined digital storefront for discovering and purchasing premium furniture collections.</p>', 1, '2025-10-31 10:30:14', NULL),
('57ad52d0-ddcc-467d-a95f-e1118fbb880f', 'Eco-Friendly Branding & Digital Campaigns for AX Recycling and Skips', 'Marketing', 'Social Media', 'AX Recycling', 'Service Industries', NULL, 'KERYAR', '2025-09-03', '/images/keryar/portfolio/cb04c669-71c4-4ff0-9d98.jpg', '<p>AX Recycling and Skips is a Melbourne-based company dedicated to providing sustainable waste management solutions. They offer services such as skip bin hire, scrap metal collection, and eco-friendly disposal options for both residential and commercial clients.</p><p>Our creative team developed a comprehensive digital identity for AX Recycling and Skips, including social media graphics, promotional campaigns, and educational content. Each visual element was designed to reflect the company\'s commitment to sustainability, efficiency, and community engagement.</p><p>The project aimed to enhance the company\'s online presence, educate the public on the importance of recycling, and establish AX Recycling and Skips as a trusted partner in eco-friendly waste management.</p>', 1, '2025-10-10 07:25:34', '2025-10-10 12:13:33'),
('5b71bc97-1bd8-49b8-926a-6ac4c1a1bffb', 'US Masters 60-Ball Cricket Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Morrisville Unity', 'Sports', NULL, 'KERYAR', '2024-04-10', '/images/keryar/portfolio/8c14e42b-d92c-426d-ad25.jpg', '<blockquote><p>Morrisville Unity T10 embraces the fast-paced excitement of high-octane, 60-ball matches. As part of the US Masters T10 circuit, the team blends international flair with local passion, engaging fans across America who love quick, result-driven cricket. Our creative approach aimed to reflect their dynamic spirit and competitive edge through visual branding, digital storytelling, and fan engagement campaigns.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity &amp; Theme:</strong> Developed a visual style (logo, colors, typography) that balances cricket’s tradition with modern energy, suited to 60-ball competition.</li><li><strong>Matchday &amp; Highlight Graphics:</strong> Created vibrant visuals for live scores, key moments, player highlights, and match recaps to engage fans in real time.</li><li><strong>Player Profiles &amp; Storytelling:</strong> Featured standout players, sharing career highlights, performance stats, and personal stories to deepen audience connection.</li><li><strong>Digital &amp; Social Campaigns:</strong> Managed content such as teasers, countdowns, match promotions, polls, and interactive posts to build anticipation and momentum.</li><li><strong>SEO &amp; Content Strategy:</strong> Produced SEO-optimized content around “Morrisville Unity T10”, “US Masters 60 ball cricket”, “US T10 cricket league” to boost online discoverability.</li><li><strong>Email Marketing:</strong> Delivered newsletters and campaign emails covering match previews, results, player insights, and fan offers to grow and nurture audience loyalty.</li></ul><p><strong>Outcome:</strong><br>This branding and campaign initiative strengthened Morrisville Unity T10’s identity within the US Masters T10 ecosystem. The consistent visual language, strategic storytelling, and fan-focused content elevated the team’s presence and helped build a dedicated following among cricket fans in the U.S.</p></blockquote>', 1, '2025-10-10 11:46:25', '2025-10-10 11:48:56');
INSERT INTO `portfolio` (`id`, `title`, `type`, `subtype`, `clientname`, `category`, `keywords`, `authorname`, `publishdate`, `coverimage`, `description`, `isactive`, `createddate`, `updateddate`) VALUES
('5bd7e66f-ecd4-4f05-bbda-e3bc61831983', 'Franchise Cricket Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Gujarat Samp Army', 'Sports', NULL, 'keryar', '2025-02-01', '/images/keryar/portfolio/7e8c5cd6-3817-4ada-9211.jpg', '<p>Gujarat Samp Army is part of the broader Samp Army franchise network, representing Gujarat in high–format cricket (such as Legend90).<br>We developed a dynamic visual identity and content strategy to reinforce the team’s positioning — power, heritage, and competitive spirit. The digital assets are designed to rally fans, spotlight performances, and establish Gujarat Samp Army as a marquee name in franchise cricket.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Team Branding:</strong> Logo refresh, color identity, typography, and brand motifs.</li><li><strong>Matchday &amp; Highlight Graphics:</strong> Visuals for live updates, scorecards, pivotal moments.</li><li><strong>Player Profiles:</strong> Spotlight content on key players with stats, hero shots, and reels.</li><li><strong>Fan Content &amp; Engagement:</strong> Polls, match predictions, behind-the-scenes, reaction posts.</li><li><strong>Promotional Campaigns:</strong> Announcements of fixtures, league tie-ups, merchandise teasers.</li></ul><p><strong>Outcome:</strong><br>The branding and campaign strengthened Gujarat Samp Army’s digital footprint, deepened fan connection, and polished their identity as a serious competitor in the Legend90 circuit. Their visuals now carry consistency, energy, and narrative — connecting on and off the pitch.</p>', 1, '2025-10-10 09:58:18', '2025-10-10 11:55:57'),
('5c5b561f-268e-47fc-b119-6d21351a115a', 'Visual Branding & Digital Presence for Shiv Dugdhalaya', 'Marketing', 'Social Media', 'shiv Dhudhalay', 'Food', NULL, 'KERYAR', '2025-10-01', '/images/keryar/portfolio/2a443543-2515-404a-abc3.jpg', '<p><strong>Shiv Dugdhalaya</strong> is a traditional dairy and sweets shop based in Anand (Gujarat), specializing in fresh milk products, desserts, and regional delicacies. Their offerings include items like <strong>rose lassi</strong>, <strong>rajbhog matho</strong>, <strong>kaju katli</strong>, and more — all crafted with local flavors and hygienic standards.</p><p>For this client, we delivered:</p><ul><li>A vibrant and appetizing visual identity reflecting the freshness and sweetness of their products</li><li>Social media content featuring product photography, menu highlights, and festival special offerings</li><li>A content strategy that balances mouth-watering visuals with brand storytelling — connecting their legacy and local roots to a wider audience</li></ul><p>The objective: to elevate Shiv Dugdhalaya’s online persona so that it resonates with customers seeking tradition, quality, and flavor — making every post feel like a taste of home.</p>', 1, '2025-10-10 06:56:05', '2025-10-10 12:16:22'),
('5d0cbb9c-f2d4-40aa-b8ef-df2889b84f75', 'Digital Home Exercise Prescription Platform & Social Media Campaigns', 'Marketing', 'Social Media', 'Yourexercises', 'Healthcare', NULL, 'KERYAR', '2024-11-01', '/images/keryar/portfolio/84c6f806-a146-4f58-a7f9.jpg', '<p>YourExercises simplifies home exercise prescription through intuitive tools for creating and customizing programs, tracking progress, and communicating with patients. The platform offers automated reminders, detailed analytics, and branded patient portals, ensuring a seamless experience for both practitioners and clients. With data privacy and reliability as top priorities, YourExercises operates smoothly across all devices — from desktops to mobile phones.</p><p><strong>Digital &amp; Social Media Marketing:</strong><br>Our creative team developed a powerful <strong>Instagram and Facebook marketing strategy</strong> to strengthen YourExercises’ online presence. The campaigns focused on educating audiences about digital rehabilitation, promoting platform features, and building brand trust among healthcare professionals.</p><ul><li><strong>Content Creation:</strong> Eye-catching visuals, feature highlights, and real user stories to showcase platform benefits.</li><li><strong>Engagement Campaigns:</strong> Polls, reels, and testimonials to connect with physiotherapists and wellness communities.</li><li><strong>Ad Strategy:</strong> Targeted social ads to reach clinics, healthcare startups, and practitioners across regions.</li></ul><p><strong>Outcome:</strong><br>The result was a cohesive digital identity and a strong social presence that positioned YourExercises.com as an innovative leader in digital physiotherapy solutions — bridging technology, healthcare, and communication for the future of rehab care.</p><p>&nbsp;</p>', 1, '2025-10-10 12:52:58', NULL),
('5eff3565-7f6d-4ed6-81ff-8ec9d797b952', 'Elevating Traditional Elegance', 'Marketing', 'Social Media', 'Plus Point', 'Fashion', NULL, 'KERYAR', '2021-12-26', '/images/keryar/portfolio/f49e5fbf-6cff-44b0-a976.jpg', '<p>Our team developed and managed Plus Point\'s digital presence, focusing on creating a cohesive and appealing online identity. Through vibrant visuals, engaging content, and strategic campaigns, we enhanced the brand\'s connection with its audience.</p><p>Key initiatives included:</p><ul><li><strong>Instagram Marketing:</strong> Regular updates featuring service highlights, client transformations, fashion tips, and promotions.</li><li><strong>Creative Design:</strong> Visually appealing graphics and photography that reflect the brand\'s modern aesthetic and commitment to quality.</li><li><strong>Digital Campaigns:</strong> Targeted promotions and collaborations to increase brand visibility and customer engagement.</li><li><strong>Community Engagement:</strong> Interactive posts and stories to foster a loyal and active online community.</li></ul><p><strong>Brand Outcome:</strong><br>Our efforts contributed to Plus Point\'s growth as a trusted destination for traditional and wedding attire, with an online presence that mirrors its dedication to excellence and customer satisfaction. Each post and campaign reinforced the brand\'s commitment to delivering exceptional fashion experiences.</p>', 1, '2025-10-11 06:44:27', NULL),
('6369515b-d85b-4a8b-b6db-7194de0edd06', 'Organic Food & Lifestyle Branding', 'Marketing', 'Social Media', 'Cofwaf', 'Food', NULL, 'KERYAR', '2025-07-10', '/images/keryar/portfolio/aa4c9950-33a3-4d6a-8f22.jpg', '<p>Soil to Soul is dedicated to promoting clean, sustainable living. Our creative work centered on building an identity that feels grounded, authentic, and nurturing. We shaped visual narratives that showcase organic ingredients, eco-friendly practices, and a connection with nature. The goal was to attract conscious consumers who value quality, health, and environmental responsibility.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Created a logo, color scheme, typography, and visual motifs inspired by nature – earthy tones, textures, and organic forms.</li><li><strong>Photography &amp; Product Styling:</strong> Styled and shot product images emphasizing natural lighting, rustic elements, and raw ingredients.</li><li><strong>Digital &amp; Social Media Campaigns:</strong> Posts and reels highlighting product origins, “farm-to-table” stories, healthy living tips, and customer testimonials.</li><li><strong>Packaging &amp; Print Collateral:</strong> Designed labels, tags, and sustainable packaging that reflect the brand’s ethos.</li><li><strong>Email Marketing:</strong> Developed newsletters that share product launches, seasonal recipes, wellness tips, and promotions.</li></ul><p><strong>Outcome:</strong><br>The campaign helped Soil to Soul deepen its connection with its target audience, increase visibility among health-conscious consumers, and establish a trustworthy, nature-aligned brand presence.</p>', 1, '2025-10-10 10:59:27', '2025-10-10 11:51:21'),
('64d142ab-1346-4d10-95c6-18f5498d38cf', 'Institutional Branding & Digital Campaigns', 'Marketing', 'Social Media', 'CES Society', 'Education', NULL, 'KERYAR ', '2025-06-12', '/images/keryar/portfolio/cafc0bcd-06e8-4c2c-a81c.jpg', '<p>CES has a rich legacy of promoting higher education in the Charotar region. Our creative team developed a contemporary digital identity that honors this heritage while resonating with the current academic community. This included designing dynamic social media visuals, crafting engaging content for events and initiatives, and creating promotional materials that reflect the society\'s commitment to academic excellence and community engagement. The project aimed to strengthen CES\'s brand presence, enhance student and alumni engagement, and showcase its diverse educational offerings.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Refreshing the society\'s visual elements to align with its values and mission.</li><li><strong>Digital Campaigns:</strong> Creating engaging content for social media platforms to promote events, initiatives, and achievements.</li><li><strong>Event Promotion:</strong> Designing promotional materials for workshops, seminars, and community service activities.</li><li><strong>Alumni Engagement:</strong> Developing content to connect with alumni and highlight their contributions to the society.</li><li><strong>Community Outreach:</strong> Crafting messages and visuals that showcase the society\'s impact on the broader community.</li></ul><p><strong>Outcome:</strong><br>The campaign successfully revitalized CES\'s digital presence, increased engagement among students and alumni, and reinforced the society\'s reputation as a leading educational institution in the Charotar region.</p>', 1, '2025-10-10 07:58:40', '2025-10-10 11:38:38'),
('67bb0692-878d-4e0a-bea6-aa64019aa10f', 'Jewellery Branding & Luxury Experience', 'Marketing', 'Social Media', 'Pramukh Jewellers', 'Jewellers', NULL, 'KERYAR', '2023-01-02', '/images/keryar/portfolio/1f4ae6fb-8fc8-4144-aee1.jpg', '<p>Pramukh Jewellers showcases an extensive collection of <strong>gold, diamond, and platinum jewellery</strong>, designed to suit every occasion — from traditional weddings to modern celebrations. Each creation is crafted with precision, certified authenticity, and attention to fine details. The brand’s expert artisans and designers bring together creativity and heritage, resulting in jewellery that reflects sophistication, grace, and tradition.</p><p>The elegant showroom is designed for comfort and luxury, featuring distinct sections for silver gifts, bridal sets, and diamond masterpieces. Every floor is curated to give customers an immersive and memorable experience, guided by knowledgeable and courteous staff.</p><p><strong>What Makes Them Stand Out:</strong></p><ul><li>A trusted legacy built over three generations.</li><li>Certified materials ensuring purity and authenticity.</li><li>A perfect balance of traditional charm and modern design.</li><li>Exceptional customer service and a luxurious showroom ambiance.</li></ul><p><strong>Brand Promise:</strong><br>Pramukh Jewellers stands for <strong>authenticity, elegance, and excellence</strong>. Each piece tells a story of heritage and innovation, offering customers not just jewellery — but timeless memories crafted with love and integrity.</p><p>&nbsp;</p>', 1, '2025-10-10 13:08:39', NULL),
('6b020acb-3228-4611-bae7-4c791a024425', 'Retail Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Mobile & More', 'Electronics', NULL, 'KERYAR', '2025-10-03', '/images/keryar/portfolio/7e14129b-1b42-4e3b-b18e.jpg', '<p>Mobile &amp; More Anand is dedicated to providing quality mobile products and services to its customers. Our creative team developed a modern digital identity that reflects the store\'s commitment to customer satisfaction and technological expertise. This included designing engaging social media visuals, crafting promotional content for new arrivals and special offers, and creating eye-catching graphics that resonate with tech enthusiasts. The project aimed to enhance Mobile &amp; More Anand\'s online presence, attract a diverse audience, and foster a sense of community among mobile technology aficionados.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Designing contemporary and appealing visuals that align with the store\'s offerings.</li><li><strong>Digital Campaigns:</strong> Creating engaging content for social media platforms to promote new arrivals, special deals, and services.</li><li><strong>Product Highlights:</strong> Showcasing featured smartphones and accessories through compelling visuals.</li><li><strong>Customer Engagement:</strong> Developing interactive posts and campaigns to connect with the local audience and encourage participation.</li><li><strong>Seasonal Promotions:</strong> Crafting visuals for festive seasons and special occasions to attract customers.</li></ul><p><strong>Outcome:</strong><br>The campaign successfully elevated Mobile &amp; More Anand\'s brand presence online, increased footfall to the store, and strengthened its reputation as a reliable destination for mobile products and services in Anand.</p>', 1, '2025-10-10 08:04:57', '2025-10-10 12:15:05'),
('6b6155dd-0e63-4152-9e27-fc8760f852ee', 'Brand Identity & Digital Campaigns for R & S Cinemas', 'Marketing', 'Social Media', 'R & S Cinemas ', 'Cinemas', NULL, 'KERYAR', '2025-07-02', '/images/keryar/portfolio/3e33e9c4-c03f-42b9-a417.jpg', '<p>R &amp; S Cinemas, located in Vivekanand Wadi, Anand, is a premier multiplex cinema hall offering a luxurious movie-watching experience. Established in 2010, it boasts state-of-the-art facilities, including Dolby Digital sound systems, silver screens, and comfortable push-back seating. With a seating capacity of over 1000, it stands as a top choice for movie enthusiasts in Anand.</p><p>Our creative team developed a comprehensive digital identity for R &amp; S Cinemas, encompassing social media graphics, promotional campaigns, and event highlights. Each visual element was crafted to reflect the cinema\'s commitment to quality entertainment, comfort, and customer satisfaction.</p><p>The project aimed to enhance the cinema\'s online presence, engage the local community, and establish R &amp; S Cinemas as the go-to destination for cinematic experiences in Anand.</p>', 1, '2025-10-10 07:36:03', NULL),
('78147eff-cfbf-4d3d-a7f4-92093c3a1d3a', 'Period & Health Tracker Mobile App', 'Development', 'Mobile App', ' Health Tracker', 'Healthcare', 'women health app, period tracker app, menstrual cycle app, fertility tracker, women wellness mobile app, health tracking UI design, modern app design, UI/UX for healthcare, lifestyle app design, menstrual calenda', 'KERYAR', '2024-01-08', '/images/keryar/portfolio/fd0fb24a-244c-4a25-a833-17976cb2403e.jpg', '<p>WomenCycle is a thoughtful and empowering mobile application created to help women track their menstrual cycle, monitor health patterns, and better understand their bodies. The design focuses on simplicity, privacy, and comfort — offering users a seamless and personal experience.</p><p><strong>Design Approach:</strong><br>The goal was to build a calm and trustworthy visual environment. The interface uses soft purple tones, rounded icons, and spacious layouts to promote ease and comfort. Every element — from the calendar to symptom tracking — is crafted for clarity and accessibility.</p><p>The app includes a daily overview, interactive cycle calendar, and customizable health tracking options. Users can log their period days, track symptoms, and set reminders for ovulation, fertility windows, or cycle phases.</p><p><strong>Development Details:</strong><br>WomenCycle’s UI is designed for scalability, supporting personalized notifications, secure data storage, and intuitive navigation. Icons and emojis were used to make symptom tracking visual and approachable. The design ensures compatibility with both Android and iOS platforms while keeping a native, fluid feel.</p><p><strong>Highlights:</strong></p><ul><li>Minimal, calming UI with soft color gradients</li><li>Intuitive calendar for tracking cycles and fertile days</li><li>Personalized health insights and reminders</li><li>Secure, user-friendly data input and profile management</li><li>Simple navigation through bottom tabs for Today, Calendar, Notifications, and Settings</li></ul><p><strong>Outcome:</strong><br>The final product is a polished, user-focused health companion app that makes period tracking simple, accurate, and empowering. WomenCycle blends emotional design with functionality — helping users stay in tune with their wellness journey while maintaining comfort and trust.</p>', 1, '2025-10-31 09:55:04', NULL),
('792d60f9-8ddb-4fda-8654-ff762096dec1', 'Cinematic Branding & Digital Engagement', 'Marketing', 'Social Media', 'Infinity Cinemas ', 'Cinemas', NULL, 'KERYAR', '2025-04-02', '/images/keryar/portfolio/4b989c0b-71eb-4bc0-b4b8.jpg', '<p>Infinity Cinemas is dedicated to providing an exceptional cinematic experience to moviegoers in Anand. Our creative team developed a dynamic digital identity that reflects the theater\'s commitment to quality and entertainment. This included designing engaging social media visuals, crafting promotional content for new releases and special offers, and creating eye-catching graphics that resonate with movie enthusiasts. The project aimed to enhance Infinity Cinemas\' online presence, attract a diverse audience, and foster a sense of community among cinema lovers.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Designing modern and appealing visuals that align with the theater\'s premium offerings.</li><li><strong>Digital Campaigns:</strong> Creating engaging content for social media platforms to promote new releases, special screenings, and offers.</li><li><strong>Event Promotion:</strong> Designing promotional materials for film festivals, themed nights, and community events.</li><li><strong>Customer Engagement:</strong> Developing interactive posts and campaigns to connect with the local audience and encourage participation.</li><li><strong>Seasonal Campaigns:</strong> Crafting visuals for festive seasons and special occasions to attract moviegoers.</li></ul><p><strong>Outcome:</strong><br>The campaign successfully elevated Infinity Cinemas\' brand presence online, increased footfall to the theater, and strengthened its reputation as a leading destination for movie enthusiasts in Anand</p>', 1, '2025-10-10 08:01:24', NULL),
('799bff69-5397-4d91-bb99-5421c0357543', 'Print Branding & Digital Campaigns', 'Marketing', 'Social Media', 'AVP Printing', 'Printing', NULL, 'KERYAR', '2025-05-01', '/images/keryar/portfolio/e61eea25-2275-4908-a544.jpg', '<p>AVP Printing specializes in bringing visual identities to life through high-quality print media. Our creative collaboration focused on not just printing, but branding — translating digital design into tangible, impactful print assets. We developed a cohesive visual language that aligns with clients’ brand identities and ensures consistency across both digital and physical media.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity Print Adaptation:</strong> Ensuring flyers, brochures, business cards, and banners carry consistent branding visuals and messaging.</li><li><strong>Promotional Campaign Print Assets:</strong> Designing posters, standees, and event graphics for marketing and events.</li><li><strong>Large Format &amp; Signage:</strong> Crafting high-impact designs for hoardings, shop signage, backdrops, and trade show displays.</li><li><strong>Digital-to-Print Translation:</strong> Converting social media graphics into print-ready formats, maintaining resolution, color fidelity, and brand integrity.</li><li><strong>Client Materials &amp; Collateral:</strong> Producing catalogues, pamphlets, branded packaging, and stationery that elevate the client’s brand presence.</li></ul><p><strong>Outcome:</strong><br>The campaign strengthened AVP Printing’s portfolio of high-quality print solutions, solidified its reputation as a trusted provider of printed branding collateral, and showcased its capability to bridge digital design with physical impact.</p>', 1, '2025-10-10 09:30:12', NULL),
('85c3ffcf-9c5c-41a1-9a9f-39f3e112b600', 'Modern Furniture eCommerce Website', 'Development', 'Website', 'IN Wood', 'Interior', 'furniture website, e-commerce design, minimal UI, UX design, online store, home decor, product showcase, interior design, modern layout', 'KERYAR', '2025-02-04', '/images/keryar/portfolio/0f3e3bdf-7df9-40a6-b766-51cc4132ca20.jpg', '<p><strong>Project Overview:</strong><br>Funiro is a clean and modern eCommerce website designed for a global furniture brand. The goal was to create a beautiful online store that makes browsing and shopping for home furniture effortless and inspiring.</p><p><strong>Design Approach:</strong><br>The design emphasizes simplicity and elegance. Neutral colors, generous white space, and high-quality product images help the furniture stand out. Each section—from featured collections to tips and inspiration—is designed to feel airy and comfortable, just like the interiors Funiro helps customers create.</p><p>We built clear navigation for <i>Products</i>, <i>Rooms</i>, and <i>Inspirations</i>, allowing visitors to explore by category or mood. Smooth transitions, clean typography, and consistent iconography keep the experience refined and professional.</p><p><strong>Development Details:</strong><br>Funiro’s website is fully responsive and optimized for performance across devices. The product catalog integrates with an intuitive cart system, product filters, and promotional tags like <i>“New”</i> and <i>“-50% Off.” </i>User engagement features such as “Add to Cart,” “Like,” and “Share” were seamlessly blended into the UI for an effortless shopping journey.</p><p><strong>Highlights:</strong></p><ul><li>Minimalist design with soft beige and neutral tones</li><li>Product grid with clean hover interactions and pricing clarity</li><li>Integrated inspiration gallery and “Tips &amp; Tricks” blog section</li><li>Focus on usability, clarity, and brand personality.</li><li>Fully mobile-friendly and SEO optimized</li></ul><p><strong>Outcome:</strong><br>The result is a visually calming, user-focused eCommerce experience that brings Funiro’s brand story to life—blending functional design with modern aesthetics to make online furniture shopping feel easy, trustworthy, and enjoyable.</p>', 1, '2025-10-31 09:39:32', NULL),
('860068c9-774f-4b4a-a1b6-958de6c3215b', 'Pet Lifestyle & Retail Branding', 'Marketing', 'Social Media', 'SkyDogs', 'Service Industries', NULL, 'KERYAR', '2024-09-10', '/images/keryar/portfolio/307e733c-077d-4bbf-8551.jpg', '<p>SkyDogs Store offers a curated selection of dog essentials — from nutritious food and treats to stylish accessories like collars, leashes, grooming tools, apparel, and play items. Each product is chosen with care, prioritizing quality, safety, and durability.</p><p>Their visual identity and digital presence center around a friendly, trustworthy, and modern aesthetic. Social media showcases cute and candid pet moments, product highlights, user testimonials, and care tips to build a community of dog lovers. The tone balances warmth with professionalism, instilling confidence in pet owners seeking reliable and stylish pet gear.</p><p>SkyDogs Store isn’t just a retailer — it’s a brand passionate about joining pet owners in their journey, offering products that delight dogs and provide peace of mind to pet parents.</p>', 1, '2025-10-11 06:25:10', NULL),
('8a221fe4-32a1-4b0d-b806-aa6bca34af31', 'Trusted Real Estate & Land Development', 'Marketing', 'Social Media', 'Shree Pancham Group', 'Real estates', NULL, 'KERYAR', '2020-12-28', '/images/keryar/portfolio/7fd740d4-e447-4fce-ac93.jpg', '<p>Our team developed and managed Shree Pancham Group\'s digital presence, focusing on creating a cohesive and appealing online identity. Through vibrant visuals, engaging content, and strategic campaigns, we enhanced the brand\'s connection with its audience.</p><p>Key initiatives included:</p><ul><li><strong>Instagram Marketing:</strong> Regular updates featuring property listings, client testimonials, and industry insights.</li><li><strong>Creative Design:</strong> Visually appealing graphics and photography that reflect the brand\'s commitment to quality and service.</li><li><strong>Digital Campaigns:</strong> Targeted promotions and collaborations to increase brand visibility and customer engagement.</li><li><strong>Community Engagement:</strong> Interactive posts and stories to foster a loyal and active online community.</li></ul><p><strong>Brand Outcome:</strong><br>Our efforts contributed to Shree Pancham Group\'s growth as a trusted name in real estate and land development, with an online presence that mirrors its dedication to excellence and customer satisfaction. Each post and campaign reinforced the brand\'s commitment to delivering exceptional real estate experiences.</p>', 1, '2025-10-11 06:56:25', '2025-10-16 12:53:28'),
('8c8b60d5-82ce-4bd9-971a-acd4a9192da9', 'Electronics Accessories Branding & Digital Strategy', 'Marketing', 'Social Media', 'UPIX ', 'Electronics', NULL, 'KERYAR', '2023-09-01', '/images/keryar/portfolio/5a388f02-9dc4-4e87-b28a.jpg', '<p>Upix Inc. specializes in manufacturing and supplying a wide range of premium electronic accessories — including remotes, power adapters, cables, travel adapters, mobile stands, laptop stands, and power strips. Every product is crafted with attention to quality, compatibility, and durability, catering to diverse environments such as homes, offices, hotels, and institutions.</p><p>The brand focuses on delivering superior customer experiences through reliable pre- and post-sales support, helping users find the right products for their needs. Upix has expanded its reach across India through both online and offline channels, establishing a strong omnichannel presence.</p><p>With a commitment to innovation and value, Upix Inc. continues to evolve by expanding its product range, improving designs, and ensuring customer satisfaction remains at the core of its growth. Trusted by thousands, Upix stands as a symbol of modern electronics solutions — reliable, affordable, and built for everyday life.</p>', 1, '2025-10-10 12:46:29', NULL),
('90ff6e0b-3252-416f-af32-52e2b328dccd', 'Renewable Energy Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Arise Solar ', 'Industries', NULL, 'KERYAR', '2025-06-03', '/images/keryar/portfolio/621f611c-ae0b-445b-abee.jpg', '<p>Arise Solar LLC is committed to clean energy and sustainability. Our creative team developed a modern, trustworthy digital identity that highlights their technical expertise and eco-friendly mission. We created social media visuals, educational content, service promotions, and campaign materials that communicate the benefits of solar energy in an engaging way.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Establishing a visual language (logos, color schemes, iconography) that conveys sustainability and innovation.</li><li><strong>Digital Campaigns:</strong> Designing content for social media that educates, engages, and promotes solar solutions.</li><li><strong>Service Promotion:</strong> Creating visual assets around solar installations, client testimonials, before/after imagery.</li><li><strong>Educational Content:</strong> Infographics, diagrams, and posts explaining solar technology, cost savings, and environmental impact.</li><li><strong>Project Showcases:</strong> Visual case studies of completed solar projects to build credibility and trust.</li></ul><p><strong>Outcome:</strong><br>The campaign helped Arise Solar LLC enhance its brand presence in the renewable energy sector, attract leads interested in sustainable solutions, and establish itself as a trusted solar services provider.</p>', 1, '2025-10-10 09:34:47', '2025-10-10 11:57:21'),
('927fcaeb-403a-4433-9629-b1a3c6bdfb44', 'Real Estate Branding & Digital Campaigns', 'Marketing', 'Social Media', 'GTA Estates', 'Real estates', NULL, 'KERYAR', '2023-08-10', '/images/keryar/portfolio/c98ba668-5ae8-4562-8888.jpg', '<p>GTA Estates aimed to strengthen its digital identity and communication strategy in the competitive Canadian real estate market. Our creative approach focused on clean, elegant visuals and trust-driven storytelling to appeal to both investors and homeowners. From online property showcases to personalized email newsletters, the campaign highlighted GTA Estates’ professionalism and commitment to client satisfaction.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Developed a cohesive visual language including logo, color palette, and typography to reflect modern elegance and reliability.</li><li><strong>Digital &amp; Social Media Content:</strong> Created high-quality visuals featuring listings, interiors, and lifestyle imagery to enhance online engagement.</li><li><strong>Email Marketing Campaigns:</strong> Designed and executed targeted email campaigns for property promotions, new listings, and client engagement — increasing inquiries and lead conversions.</li><li><strong>Client Testimonials &amp; Case Studies:</strong> Built credibility through content showcasing successful deals and client experiences.</li><li><strong>Promotional Materials:</strong> Designed digital brochures, event banners, and print media assets for property launches and open houses.</li></ul><p><strong>Outcome:</strong><br>The campaign successfully elevated GTA Estates’ brand presence across Ontario, enhanced digital engagement, and strengthened client trust through consistent branding and strategic email outreach.</p>', 1, '2025-10-10 10:13:48', '2025-10-11 05:59:42'),
('94a2df2d-047c-4787-93d9-b1665b6a952e', 'Your Pathway to IELTS Success', 'Marketing', 'Social Media', 'Sumeru Acedemy', 'Education', NULL, 'KERYAR', '2024-03-04', '/images/keryar/portfolio/6320bc29-d33d-46f5-97a9.jpg', '<p>Our team developed and managed Sumeru Academy\'s digital presence, focusing on creating a cohesive and appealing online identity. Through vibrant visuals, engaging content, and strategic campaigns, we enhanced the brand\'s connection with its audience.</p><p>Key initiatives included:</p><ul><li><strong>Instagram Marketing:</strong> Regular updates featuring student success stories, course offerings, and motivational content.</li><li><strong>Creative Design:</strong> Visually appealing graphics and photography that reflect the academy\'s commitment to quality education.</li><li><strong>Digital Campaigns:</strong> Targeted promotions and collaborations to increase brand visibility and student engagement.</li><li><strong>Community Engagement:</strong> Interactive posts and stories to foster a supportive and active online community.</li></ul><p><strong>Brand Outcome:</strong><br>Our efforts contributed to Sumeru Academy\'s growth as a trusted destination for IELTS preparation, with an online presence that mirrors its dedication to student success and excellence in education.</p>', 1, '2025-10-11 06:59:31', '2025-10-16 12:53:14'),
('975f3b5b-40b0-443f-9d69-6d3994ebb687', 'Brand Strategy & Digital Identity for SampGroup', 'Marketing', 'Social Media', 'Sampgroup', 'Sports', NULL, 'KERYAR', '2025-10-05', '/images/keryar/portfolio/068c04f1-899e-46ac-85fa.jpg', '<p><strong>SampGroup</strong> is a multi-vertical organization built on the belief that <i>“SAMP means UNITY.”</i> The brand represents collaboration, loyalty, and growth across diverse sectors including cricket, healthcare, real estate, and technology.</p><p>Our team developed a cohesive digital identity and content strategy to reflect SampGroup’s values — bringing together modern design, consistent branding, and storytelling that highlights their journey from a passionate community to a powerful brand family.</p><p>The project focused on crafting impactful visuals, unified brand communication, and an online presence that celebrates teamwork, innovation, and expansion under one vision — <strong>Unity in Growth.</strong></p>', 1, '2025-10-10 06:46:54', '2025-10-10 12:16:36'),
('9c3cc9b7-0016-40f0-b833-c584a8066b74', 'Peperz – Creative Digital Agency Website', 'Development', 'Website', 'Peperz', 'Industries', 'creative agency website, digital marketing web design, branding agency website, ui ux design, portfolio web design, modern corporate website, business website design, creative studio web development, digital agency landing page, marketing website design', 'KERYAR', '2024-05-15', '/images/keryar/portfolio/3973aab3-0974-4fa8-8925-ff47146da0cd.jpg', '<p><strong>Project Overview:</strong><br>Peperz is a <strong>modern creative digital agency website</strong> built to highlight the company’s expertise in branding, UI/UX, development, and marketing. The goal was to design a digital presence that feels bold, confident, and creative — one that speaks directly to clients looking for design-driven business growth.</p><p><strong>Design Approach:</strong><br>The design blends <strong>strong visual hierarchy</strong> with a clean, minimal layout. A warm and bright color palette, paired with confident typography, creates an energetic yet professional look. The hero section instantly captures attention with a powerful message — <i>“Unlock your business potential”</i> — setting a forward-thinking tone from the start.</p><p>The structure emphasizes storytelling:</p><ul><li><strong>Services</strong> are presented in clean cards (UI/UX, Development, Brand Design, Marketing).</li><li><strong>About section</strong> showcases personality, achievements, and credibility.</li><li><strong>Portfolio grid</strong> highlights creative projects with large visuals.</li><li><strong>FAQ and testimonial sections</strong> build trust and transparency.</li><li><strong>Contact and newsletter sections</strong> encourage connection and engagement.</li></ul><p><strong>Development Details:</strong><br>The Peperz website is fully responsive and built for performance across all devices. Smooth animations and hover transitions enhance the browsing experience. The backend is optimized for easy updates, enabling the client to manage content and showcase new projects without technical barriers.</p><p><strong>Highlights:</strong></p><ul><li>Bold and creative agency-style layout</li><li>Responsive, fast-loading, and SEO-friendly build</li><li>Structured sections for services, portfolio, and team</li><li>Clean navigation and user-focused interaction</li><li>Warm color accents to balance creativity and professionalism</li><li>Engaging newsletter and contact CTAs for conversions</li></ul><p><strong>Outcome:</strong><br>Peperz’s new website positions the agency as a creative leader with a modern digital identity. It communicates trust, clarity, and innovation — helping the brand connect with clients, showcase their work, and grow their digital presence effectively.</p>', 1, '2025-10-31 10:34:04', '2025-10-31 10:47:55'),
('a74dea82-ff17-4405-a8f6-9e88ea2856f2', 'Sports Branding & Digital Campaigns for Vadodara Cricket Academy', 'Marketing', 'Social Media', 'Vadodara Cricket Academy', 'Sports', NULL, 'KERYAR', '2025-09-14', '/images/keryar/portfolio/3fac6dad-5f6a-4271-ad59.jpg', '<p>Vadodara Cricket Academy is a premier cricket training institution nurturing young talent in Baroda and beyond. With a focus on skill development, discipline, and sportsmanship, the academy has become a hub for aspiring cricketers aiming for professional success.</p><p>Our creative team developed a vibrant and engaging digital identity for the academy — including social media graphics, training highlights, event promotions, and player spotlights. Each visual element was designed to reflect the academy’s commitment to excellence, growth, and the spirit of cricket.</p><p>The project’s goal was to strengthen the academy’s online presence, inspire young athletes, and create a cohesive brand image that resonates with players, parents, and fans alike.</p>', 1, '2025-10-10 07:12:54', '2025-10-10 12:13:13'),
('aeeefcad-bb50-45a0-bd8b-f454c8ab987b', 'Creative Design & Visual Identity', 'Marketing', 'Social Media', 'Mansory Design', 'Interior', NULL, 'KERYAR', '2025-03-07', '/images/keryar/portfolio/962938c3-f9c0-40e3-a976.jpg', '<p>Mansory Design wanted a refined, stylish identity that speaks to quality, sophistication, and modern design sensibilities. The goal was to produce visual content that balances creativity with elegance — something that appeals to discerning clients, art lovers, and high-end markets. We crafted a design language that’s expressive yet coherent, making every project visually striking and aligned with the brand’s voice.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Defining visual style — logos, color palette, typography — that capture a premium, refined look.</li><li><strong>Portfolio &amp; Project Imagery:</strong> Producing high-quality visuals, photographs or renders, mood boards, and case studies to showcase design projects.</li><li><strong>Digital Presence:</strong> Social media visuals, posts, stories, and other digital assets to communicate design philosophy and attract clients.</li><li><strong>Campaigns &amp; Concepts:</strong> Thematic design campaigns (launches, collaborations, new offerings) with consistent visual storytelling.</li><li><strong>Client Marketing Materials:</strong> Brochures, proposals, presentations, and possibly website or print collateral that reflect the brand’s style.</li></ul><p><strong>Outcome:</strong><br>The brand identity and visual strategy elevated Mansory Designs portfolio impact, increased recognition in creative circles, and helped attract clients looking for high-quality, design-led work. The coherent visual expression and consistent branding across platforms built trust and aesthetic appreciation among its audience.</p>', 1, '2025-10-10 10:19:21', NULL),
('b0e7f25b-111c-470e-b81b-c9c75800ed38', 'Beauty & Wellness Branding', 'Marketing', 'Social Media', 'House of Glam', 'Fashion', NULL, 'KERYAR', '2024-01-10', '/images/keryar/portfolio/3177eb96-2e83-419d-93cd.jpg', '<p>Our team developed and managed House of Glam\'s digital presence, focusing on creating a cohesive and appealing online identity. Through vibrant visuals, engaging content, and strategic campaigns, we enhanced the brand\'s connection with its audience.</p><p>Key initiatives included:</p><ul><li><strong>Instagram Marketing:</strong> Regular updates featuring service highlights, client transformations, beauty tips, and promotions.</li><li><strong>Creative Design:</strong> Visually appealing graphics and photography that reflect the salon\'s modern aesthetic and commitment to quality.</li><li><strong>Digital Campaigns:</strong> Targeted promotions and collaborations to increase brand visibility and customer engagement.</li><li><strong>Community Engagement:</strong> Interactive posts and stories to foster a loyal and active online community.</li></ul><p><strong>Brand Outcome:</strong><br>Our efforts contributed to House of Glam\'s growth as a trusted beauty destination, with an online presence that mirrors its dedication to excellence and customer satisfaction. Each post and campaign reinforced the brand\'s commitment to delivering exceptional beauty experiences.</p>', 1, '2025-10-11 06:42:30', '2025-10-16 12:58:25'),
('b34da867-cf55-42f7-859b-28e7434314be', 'Digital Awareness Campaign for Himalaya Hospital', 'Marketing', 'Social Media', 'Himalaya Hospital', 'Healthcare', NULL, 'Keryar', '2025-08-13', '/images/keryar/portfolio/c8e5c68b-e48c-4a94-be87.jpg', '<p>Our team collaborated with <strong>Himalaya Hospital</strong> to design a digital awareness campaign focused on women’s health, maternity care, and advanced surgical techniques. The campaign highlighted key healthcare topics such as high-risk pregnancy care, laparoscopic surgery, and minimal invasive procedures — all crafted with informative visuals and compassionate messaging.</p><p>Through thoughtful design and clear communication, we helped Himalaya Hospital strengthen its online presence and connect with patients by spreading trust, awareness, and expert care through social media.</p>', 1, '2025-10-09 13:23:52', '2025-10-10 12:17:31'),
('b6081cd1-7500-421b-814a-3585b4199695', 'Brand Identity & Digital Campaigns for Mira Homeopathic', 'Marketing', 'Social Media', 'Mira Homepathic Store', 'Healthcare', NULL, 'KERYAR', '2025-07-08', '/images/keryar/portfolio/263eb6c6-de91-4637-b8b4.jpg', '<p>Mira Homeopathic is a trusted homeopathic clinic located in Anand, Gujarat. Established in 1973, the clinic has been serving the community for over five decades, offering holistic treatments for various health concerns. Their services encompass a wide range of conditions, including hair fall, skin disorders, respiratory issues, stomach ailments, infertility, chronic diseases, psychological conditions, and more. <a href=\"https://www.justdial.com/Anand/Mira-Homeopathic-Biochemic-Medical-Store-Opposite-Railway-Godi-Sardarganj/9999P2692-2692-150528183347-E8U5_BZDET?utm_source=chatgpt.com\">Justdial+1</a></p><p>Our creative team developed a comprehensive digital identity for Mira Homeopathic, including social media graphics, patient testimonials, and informative content. Each visual element was crafted to reflect the clinic\'s commitment to holistic health, trust, and personalized care.</p><p>The project aimed to enhance the clinic\'s online presence, educate the community about the benefits of homeopathy, and establish Mira Homeopathic as a trusted partner in natural healing.</p>', 1, '2025-10-10 07:28:42', '2025-10-10 12:17:18'),
('b83a340a-4278-4a49-9c27-a597f7bb0d60', 'Business Phone System Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Dial Raven ', 'Service Industries', NULL, 'KERYAR', '2024-05-10', '/images/keryar/portfolio/db715e8e-8d05-4771-b8eb.jpg', '<p>DialRaven offers easy-to-use, scalable, cloud-based business phone systems that integrate smoothly into various industry settings. The service is built for organizations that need reliable, professional call handling, extensions, customer support lines, and unified communication across teams and locations.</p><p><strong>Detailed Description:</strong><br>The branding and digital campaign for DialRaven centered on clarity, trust, and industry versatility. We crafted a visual identity and messaging platform that conveys efficiency, reliability, and modern connectivity. Emphasis was placed on highlighting how DialRaven supports critical sectors — retail, healthcare, hospitality, restaurants, automotive — with robust communication infrastructure.</p><p>We developed digital content such as explainer graphics, feature highlight posts, case studies, and testimonials to demonstrate real-world value. The tone is professional yet approachable, underlining how even complex telephony systems can feel simple in use. The campaign also included educational content — e.g. benefits, how it works, integration features — aimed at decision makers.</p>', 1, '2025-10-10 13:00:30', NULL),
('b8f49269-f8c7-44ca-a5ff-5ae6870b3369', 'Agrios – Organic Agriculture & Farm Products Website', 'Development', 'Website', 'Agrios', 'Service Industries', 'agriculture website design, organic farm website, ecommerce development, organic food store, farm products online shop, UI/UX design, responsive web design, natural food ecommerce, sustainable farming website, web development portfolio', 'KERYAR', '2024-03-06', '/images/keryar/portfolio/15be9c62-4395-4137-bf20-c77636188ee8.jpg', '<p>Agrios is a professionally designed <strong>organic farming and agricultural products website</strong> built to highlight healthy, sustainable living. The website blends a natural aesthetic with a structured eCommerce experience, making it easy for customers to explore fresh produce and shop online.</p><p><strong>Design Approach:</strong><br>The design uses earthy greens, soft whites, and natural imagery to reflect the brand’s organic roots. From the hero banner featuring real farmers to product listings showcasing fruits, vegetables, and farm goods, every section conveys freshness and trust.</p><p>The homepage introduces visitors to Agrios’ values—quality, sustainability, and care—while strategically placed calls to action guide them to shop or learn more. The layout is clean, with high readability and consistent use of modern typography.</p><p><strong>Development Details:</strong><br>The site was developed with a focus on usability and conversion. Built with responsive front-end design and a strong eCommerce backend, it supports product filtering, cart management, and discount features. Integrated sections like <i>customer reviews,</i> <i>blog posts,</i> and <i>featured products</i> add authenticity and engagement.</p><p><strong>Highlights:</strong></p><ul><li>Fully responsive website for desktop, tablet, and mobile</li><li>eCommerce integration for online orders</li><li>Product cards with pricing, sale labels, and call-to-action buttons</li><li>Sustainable, nature-inspired color palette</li><li>Customer testimonials and featured blog articles</li><li>Optimized for speed, SEO, and user experience</li></ul><p><strong>Outcome:</strong><br>The final website delivers a professional and trustworthy digital presence for Agrios Organic Farms. It helps the brand connect directly with customers, promote healthy living, and grow its business through a visually appealing and high-performing eCommerce platform.</p>', 1, '2025-10-31 10:24:36', NULL),
('baf0b103-ab51-40d5-a703-be137aab79b8', 'Fertility & Reproductive Care Branding & Digital Campaigns', 'Marketing', 'Social Media', 'ZenIVF', 'Healthcare', NULL, 'KERYAR', '2024-10-22', '/images/keryar/portfolio/a5bf2ea7-12e9-447a-bfce.jpg', '<p>At Zen IVF, the approach is rooted in both clinical excellence and emotional sensitivity. The clinic offers services in IVF (in vitro fertilization), fertility evaluation, hormonal balancing, and integrative therapies that enhance reproductive wellbeing. Their brand identity reflects calmness, hope, and trust: soft color palettes, clean typography, and visuals that convey serenity and confidence.</p><p>The digital strategy includes content that educates (fertility facts, treatment steps, patient stories), reassures (clinic philosophy, success stories, staff credentials), and engages (Q&amp;A sessions, patient testimonials, behind-the-scenes). Strong emphasis is placed on building trust through transparency, clear process explanations, and human stories.</p><p>Through this combined branding and digital path, Zen IVF positions itself not just as a medical facility, but as a caring partner in the journey toward new life.</p>', 1, '2025-10-10 12:56:23', NULL),
('c397fdce-9337-47ea-bb7e-812d8b22f824', 'Brand Identity & Digital Campaigns for Narayan Developer', 'Marketing', 'Social Media', 'Narayan', 'Real estates', NULL, 'KERYAR', '2025-07-08', '/images/keryar/portfolio/664d7da6-772c-4bfe-974c.jpg', '<p>Narayan Developer is a real estate / property development firm operating in Anand, Gujarat, known for premium residential &amp; commercial projects like <strong>Narayan Exotica</strong> in Bakrol and <strong>Narayan Empire</strong> in Anand.</p><p>Our creative team developed a modern and aspirational identity across their digital presence — including campaign visuals, project highlight reels, client communication content, property brochures, and social media storytelling. Each piece was made to reflect quality, trust, and the luxury-lifestyle positioning of their offerings.</p><p>The project’s goal was to reinforce Narayan Developer’s brand as a reliable, upscale real estate choice in Anand, to attract potential homeowners/investors, and to communicate the unique amenities and lifestyle value their projects offer.</p>', 1, '2025-10-10 07:41:46', NULL),
('c49e2899-d643-4fc1-b8ae-7f8720d2b503', 'Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Vastra', 'Food', NULL, 'KERYAR', '2025-08-07', '/images/keryar/portfolio/a022d079-b3a5-4ba7-a5ef.jpg', '<p>Vatsa Supermarket is known for its customer-centric approach and quality products. Our creative team developed a vibrant and engaging digital identity — from social media visuals and promotional campaigns to product highlights and festive offers. Every design was crafted to reflect the supermarket’s commitment to quality, convenience, and community connection. The project aimed to strengthen Vatsa Supermarket’s brand presence online, drive customer engagement, and enhance footfall in-store.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Designing consistent visuals and graphics that align with the supermarket’s image.</li><li><strong>Digital Campaigns:</strong> Creating engaging social media content for promotions, offers, and seasonal campaigns.</li><li><strong>Product Highlights:</strong> Showcasing products and special deals through eye-catching visuals.</li><li><strong>Customer Engagement:</strong> Developing interactive posts and reels to connect with the local community.</li><li><strong>Festive Campaigns:</strong> Designing creative assets for Diwali, Navratri, and other seasonal events.</li></ul><p><strong>Outcome:</strong><br>The campaign successfully increased Vatsa Supermarket’s online presence, enhanced customer engagement, and reinforced its reputation as a trusted retail destination for quality products.</p>', 1, '2025-10-10 07:48:14', '2025-10-10 12:15:18');
INSERT INTO `portfolio` (`id`, `title`, `type`, `subtype`, `clientname`, `category`, `keywords`, `authorname`, `publishdate`, `coverimage`, `description`, `isactive`, `createddate`, `updateddate`) VALUES
('c80e90ec-4855-4832-ac3e-8b085dcec95c', 'Electric Vehicle Branding & Digital Campaigns', 'Marketing', 'Social Media', 'SuperEco EV', 'AutoMobile', NULL, 'KERYAR', '2025-10-10', '/images/keryar/portfolio/a0d2002c-aa48-4e76-a016.jpg', '<p>SuperEco EV envisions a cleaner future by making electric mobility accessible, stylish, and efficient. Our creative collaboration focused on building a digital identity that captures the brand’s eco-friendly mission and technological promise. From product showcases to promotional campaigns, we aimed to present SuperEco EV as not just a vehicle brand, but a movement toward sustainable living.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity &amp; Messaging:</strong> Developing visuals, taglines, and tone that emphasize sustainability, innovation, and reliability.</li><li><strong>Product Campaigns:</strong> Showcasing key models (like the S1) with highlight features — battery life, BLDC motor power, warranty, etc. </li><li><strong>Social Media Content:</strong> Posts, reels, and slides focusing on vehicle features, user benefits (low running cost, zero emissions), and brand ethos</li><li><strong>Dealer / Franchise Promotion:</strong> Campaigns encouraging business partners to invest in EV dealerships. </li><li><strong>Performance &amp; Technology Highlights:</strong> Visuals and copy emphasizing instant torque, high output motors, warranties, and battery capabilities.&nbsp;</li></ul><p><strong>Outcome:</strong><br>The campaign helped SuperEco EV strengthen its brand presence in the electric vehicle segment, communicated its core advantages (eco-friendly, cost-efficient, high performance), and engaged audiences who are interested in making the shift to greener transport options.</p>', 1, '2025-10-10 10:07:08', '2025-10-10 11:55:44'),
('cb11da3f-983e-4358-8791-20bc351f7561', 'Taskit – Task Management & Productivity Mobile App', 'Development', 'Mobile App', 'Taskit', 'Service Industries', 'task management app, productivity app, mobile ui design, team collaboration app, project tracker, to-do list app design, daily planner ui, task tracker mobile app, modern ux design, business app ui design', 'KERYAR', '2024-12-10', '/images/keryar/portfolio/891f3344-25d1-41dd-b9b2-4266b4dfac8e.jpg', '<p>Taskit is a modern and efficient mobile application designed to help individuals and teams organize their daily tasks, manage projects, and improve productivity. The app delivers a clean, intuitive interface that makes creating, tracking, and completing tasks effortless.</p><p><strong>Design Approach:</strong><br>The design focuses on clarity and balance — using shades of deep violet and white for a professional yet friendly look. Each screen is structured to keep users focused and motivated, from logging in to checking progress across tasks.</p><p>We prioritized easy navigation and smooth transitions between states like “My Tasks,” “In Progress,” and “Completed.” The dashboard provides a quick snapshot of deadlines, progress percentages, and team assignments, making it simple to stay on track.</p><p><strong>Development Details:</strong><br>Taskit’s interface is designed to handle multi-user collaboration, progress tracking, and scheduling with built-in calendar integration. Users can create projects, assign members, set due dates, and track performance visually through progress circles and category tags.</p><p><strong>Highlights:</strong></p><ul><li>Clean and minimal interface with violet gradient accents</li><li>Simple navigation for creating, managing, and completing tasks</li><li>Team collaboration tools with member assignment</li><li>Progress tracking via visual indicators and charts</li><li>Integrated calendar for due dates and scheduling</li><li>Fully responsive design optimized for both Android and iOS</li></ul><p><strong>Outcome:</strong><br>The result is a sleek and reliable productivity tool that helps users plan their day, manage projects, and stay accountable. Taskit turns everyday task management into an organized, visually engaging experience that boosts efficiency and teamwork.</p>', 1, '2025-10-31 10:01:38', NULL),
('ce89a5d9-b114-40ce-9904-16813170d191', 'Automotive Showroom & Service Brand Identity', 'Marketing', 'Social Media', 'Amber Automobiles Dahod', 'Service Industries', NULL, 'KERYAR', '2025-07-03', '/images/keryar/portfolio/94388667-d19d-4443-97c8.jpg', '<p>The showroom is designed to deliver a <strong>premium car-buying experience</strong>, showcasing the latest Mahindra models in a spacious and modern environment. With a strong emphasis on customer comfort and transparency, the team ensures every visitor receives expert guidance in choosing the perfect vehicle.</p><p>Amber Automobiles also operates a <strong>state-of-the-art service center</strong>, equipped with advanced tools and trained technicians who provide quality maintenance, repair, and after-sales support. Every detail — from brand visuals to client interactions — reflects Mahindra’s spirit of innovation and rugged excellence.</p><p><strong>Brand Essence:</strong><br>Amber Automobiles represents <strong>trust, performance, and commitment</strong>. Their focus on delivering exceptional service and fostering long-term relationships has made them one of Dahod’s most respected names in the automobile industry.</p>', 1, '2025-10-10 13:12:13', NULL),
('d11dfd50-44a7-4faa-806c-c8b6f26487b7', 'Hedy Agency – Creative Digital Makers Website', 'Development', 'Website', 'Hedy Agency', 'Technology', 'digital agency website, creative studio web design, modern tech website, ui ux design agency, branding website, French creative agency, minimal design Webflow site, digital experience agency, portfolio website design, web design inspiration', 'KERYAR', '2023-09-18', '/images/keryar/portfolio/15285dd6-7d85-4f26-9e8e-955f48f41d03.jpg', '<p><strong>Project Overview:</strong><br>Hedy Agency is a <strong>French creative and digital strategy studio</strong> that helps brands grow through simplicity, clarity, and design thinking. The website captures the agency’s modern and tech-forward spirit with a bold, minimal layout and a sharp visual identity.</p><p><strong>Design Approach:</strong><br>The website embraces a <strong>black and gradient purple-blue theme</strong>, exuding confidence and digital sophistication. The opening line—“digital<i> makers”</i>—instantly defines the brand’s identity.<br>Strong typography, high contrast, and smooth motion effects make the user experience both engaging and effortless.</p><p>Each section reflects purpose and clarity:</p><ul><li><strong>Hero Section:</strong> Powerful typography with motion elements and an intro video.</li><li><strong>Offers Section:</strong> Clearly defined packages—Wrap, <i>Toast</i>, and <i>Club</i>—explaining services from SEO and strategy to design and collaboration.</li><li><strong>Methodology Section:</strong> Introduces tools and workflow—Figma, Asana, Webflow, and custom development—showing the agency’s modern process.</li><li><strong>Projects Section:</strong> Displays previous works in a clean, image-focused layout.</li><li><strong>Footer:</strong> Minimal yet informative, with sustainability and contact details integrated.</li></ul><p>The UX design follows a balance between <strong>creative freedom and structured hierarchy</strong>, keeping information accessible while maintaining a distinct personality.</p><p><strong>Development Details:</strong><br>Built using <strong>Webflow</strong> for a dynamic and flexible design system, the site prioritizes performance and modular content updates. Subtle transitions and micro-animations elevate the experience without overwhelming users.</p><p><strong>Highlights:</strong></p><ul><li>Bold, minimal, and tech-inspired layout</li><li>Clean French typography with gradient visual cues</li><li>Interactive elements for engagement (videos, scroll effects, animations)</li><li>Clearly defined service offerings</li><li>Smooth, responsive design optimized for all devices</li><li>Webflow-powered backend for easy scalability</li></ul><p><strong>Outcome:</strong><br>The Hedy Agency website perfectly communicates the brand’s ethos—simplicity,<i> flexibility, and collaboration.</i> It positions Hedy as a modern creative partner for digital projects, blending functionality with artful design.</p>', 1, '2025-10-31 10:53:37', NULL),
('d7f6345a-0d7a-4137-936f-5ef4ad43d2fa', 'Crafting Timeless Elegance', 'Marketing', 'Social Media', 'Sahjanand Jewllers', 'Jewellers', NULL, 'KERYAR', '2023-01-31', '/images/keryar/portfolio/17bb65d7-b284-4ab0-98d8.jpg', '<p>Our team developed and managed Sahjanand Art Jewellers\' digital presence, focusing on creating a cohesive and appealing online identity. Through vibrant visuals, engaging content, and strategic campaigns, we enhanced the brand\'s connection with its audience.</p><p>Key initiatives included:</p><ul><li><strong>Instagram Marketing:</strong> Regular updates featuring product highlights, customer testimonials, and behind-the-scenes content.</li><li><strong>Creative Design:</strong> Visually appealing graphics and photography that reflect the brand\'s dedication to quality and tradition.</li><li><strong>Digital Campaigns:</strong> Targeted promotions and collaborations to increase brand visibility and customer engagement.</li><li><strong>Community Engagement:</strong> Interactive posts and stories to foster a loyal and active online community.</li></ul><p><strong>Brand Outcome:</strong><br>Our efforts contributed to Sahjanand Art Jewellers\' growth as a trusted destination for fine jewellery, with an online presence that mirrors its dedication to excellence and customer satisfaction. Each post and campaign reinforced the brand\'s commitment to delivering exceptional jewellery experiences.</p>', 1, '2025-10-11 06:47:18', NULL),
('df7db311-8aaf-44ae-866d-9ff5a3fdf084', 'Complete Social Media & Digital Marketing by Our Team', 'Marketing', 'Social Media', 'Oriole Pizza', 'Food', NULL, 'KERYAR', '2023-11-07', '/images/keryar/portfolio/0c028ed8-2f66-4d58-a847.jpg', '<p>Our team managed the <strong>entire digital presence and marketing strategy</strong> for Oriole Pizza — from social media branding to creative campaigns and content design. We built a strong, engaging identity across Instagram through vibrant visuals, dynamic reels, and mouthwatering photography.</p><p>We focused on:</p><ul><li><strong>Instagram Marketing:</strong> Consistent content calendar featuring product highlights, special offers, customer stories, and engaging reels.</li><li><strong>Creative Design:</strong> Bold layouts, appetizing visuals, and catchy copy to reflect freshness and fun.</li><li><strong>Digital Campaigns:</strong> Targeted ads, festive promotions, and influencer tie-ups to expand reach and brand recall.</li><li><strong>Community Building:</strong> Interactive polls, contests, and story updates to drive engagement and loyalty.</li></ul><p><strong>Brand Outcome:</strong><br>Through a well-planned digital strategy, Oriole Pizza’s online presence evolved into a <strong>vibrant food brand loved by its audience</strong>. Each post tells a story — of flavor, community, and the joy of great pizza shared together.</p><p><strong>Essence:</strong><br>Bold flavors. Fresh visuals. A pizza brand that’s as creative online as it is in the kitchen.</p><p>&nbsp;</p>', 1, '2025-10-11 06:33:44', '2025-10-17 05:23:38'),
('e00025ab-6118-44ab-a520-e75602f24652', 'Retail Branding & Digital Campaigns', 'Marketing', 'Social Media', 'Peachgrove Wine Spirits', 'Food', NULL, 'KERYAR', '2025-06-02', '/images/keryar/portfolio/d51a519c-5db3-46a4-96f3.jpg', '<p>Peachgrove\'s Wine and Spirits is dedicated to providing quality products and exceptional customer service. Our creative team developed a sophisticated digital identity that reflects the store\'s commitment to excellence and community engagement. This included designing elegant social media visuals, crafting promotional content for new arrivals and special offers, and creating eye-catching graphics that resonate with beverage enthusiasts. The project aimed to enhance Peachgrove\'s online presence, attract a diverse audience, and foster a sense of community among customers.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity:</strong> Designing refined and appealing visuals that align with the store\'s premium offerings.</li><li><strong>Digital Campaigns:</strong> Creating engaging content for social media platforms to promote new arrivals, special deals, and events.</li><li><strong>Product Highlights:</strong> Showcasing featured wines and spirits through compelling visuals.</li><li><strong>Customer Engagement:</strong> Developing interactive posts and campaigns to connect with the local audience and encourage participation.</li><li><strong>Seasonal Promotions:</strong> Crafting visuals for festive seasons and special occasions to attract customers.</li></ul><p><strong>Outcome:</strong><br>The campaign successfully elevated Peachgrove\'s Wine and Spirits\' brand presence online, increased footfall to the store, and strengthened its reputation as a trusted destination for quality beverages.</p>', 1, '2025-10-10 08:13:46', '2025-10-10 12:12:43'),
('e16d5e74-b583-464e-8a8c-cd422aa0a3e0', 'ProCleaning – Professional Cleaning Services Website', 'Development', 'Website', 'ProCleaning', 'Service Industries', 'cleaning service website, cleaning company web design, housekeeping website design, business website, cleaning agency website, cleaning booking website, home cleaning services web design, professional cleaning company, responsive service website, corporate web design', 'KERYAR', '2024-01-31', '/images/keryar/portfolio/3234101c-abc3-4de1-84ce-ddc9de12f1b7.jpg', '<p><strong>Project Overview:</strong><br>ProCleaning is a <strong>modern and professional cleaning services website</strong> built for a company that offers residential and commercial cleaning solutions. The goal was to create a clean, confident, and approachable digital presence that reflects reliability, quality service, and customer care.</p><p><strong>Design Approach:</strong><br>The website uses a <strong>fresh green-and-white color palette</strong> to symbolize cleanliness, balance, and eco-friendliness. The hero section immediately builds trust with a team photo and a bold headline: <i>“Specialized, efficient, and thorough cleaning services.”</i><br>The structure focuses on clarity and easy navigation — allowing users to quickly learn about services, view pricing, and make bookings.</p><p>Each section serves a clear purpose:</p><ul><li><strong>Service Overview:</strong> Office, Spring, and House Cleaning showcased with direct “Book Now” calls-to-action.</li><li><strong>Pricing Plans:</strong> Transparent and easy-to-compare packages for different client needs.</li><li><strong>About and Testimonials:</strong> Build credibility with client reviews and team highlights.</li><li><strong>Blog Section:</strong> Offers cleaning tips and eco-friendly practices to engage readers.</li><li><strong>Contact Section:</strong> Clear and accessible, with inquiry form and call-to-action buttons.</li></ul><p>Typography is simple and professional, complemented by friendly imagery that creates an approachable, service-oriented feel.</p><p><strong>Development Details:</strong><br>The website is fully responsive and optimized for performance across devices. The CMS enables quick service updates, new blog posts, and package changes. Animations are subtle, enhancing engagement without distracting from usability.</p><p><strong>Highlights:</strong></p><ul><li>Modern and clean UI design focused on service clarity</li><li>Easy navigation and structured content hierarchy</li><li>Real customer testimonials and team photos for trust</li><li>Transparent pricing section with “Book Now” flow</li><li>Blog integration for SEO and user engagement</li><li>Responsive, SEO-friendly, and conversion-optimized</li></ul><p><strong>Outcome:</strong><br>ProCleaning’s website creates a strong online presence that reflects its professionalism and customer-first values. The intuitive structure and clean design make it easy for users to explore services, compare plans, and book with confidence — driving both credibility and conversion.</p>', 1, '2025-10-31 10:43:16', NULL),
('e21393b3-d1df-4878-8491-3d1ab1ae2e0f', 'Precision Skincare, Expertly Delivered', 'Marketing', 'Social Media', 'Kaya Lesar Studio', 'Service Industries', NULL, 'KERYAR', '2024-11-29', '/images/keryar/portfolio/f9ea1699-9d7e-49d6-8693.jpg', '<p>Our team managed Kaya Laser Studio\'s digital presence, focusing on creating a cohesive and appealing online identity. Through vibrant visuals, engaging content, and strategic campaigns, we enhanced the brand\'s connection with its audience.</p><p>Key initiatives included:</p><ul><li><strong>Instagram Marketing:</strong> Regular updates featuring service highlights, client transformations, skincare tips, and promotions.</li><li><strong>Creative Design:</strong> Visually appealing graphics and photography that reflect the studio\'s modern aesthetic and commitment to quality.</li><li><strong>Digital Campaigns:</strong> Targeted promotions and collaborations to increase brand visibility and customer engagement.</li><li><strong>Community Engagement:</strong> Interactive posts and stories to foster a loyal and active online community.</li></ul><p><strong>Brand Outcome:</strong><br>Our efforts contributed to Kaya Laser Studio\'s growth as a trusted destination for skincare and laser treatments, with an online presence that mirrors its dedication to excellence and customer satisfaction. Each post and campaign reinforced the brand\'s commitment to delivering exceptional beauty experiences.</p>', 1, '2025-10-11 06:54:09', '2025-10-16 12:55:35'),
('e505130f-be22-4f49-a67e-efaedee44f21', 'Study Abroad & Migration Partner', 'Marketing', 'Social Media', 'global eye consultant', 'Education', NULL, 'KERYAR', '2024-12-12', '/images/keryar/portfolio/65c9d76a-4004-469e-b7a5.jpg', '<p>Global Eye provides <strong>end-to-end study abroad services</strong> — from university selection and application support to visa guidance and pre-departure preparation. Their experienced counselors help students identify the right course and country based on their academic profile, career goals, and financial capacity.</p><p>The consultancy also offers <strong>language and test preparation</strong> for IELTS, PTE, and other proficiency exams, along with expert assistance in documentation, SOP writing, and scholarship guidance. Through structured counseling and constant mentorship, Global Eye ensures that students feel confident and well-prepared for their international education experience.</p><p><strong>Brand Essence:</strong><br>Global Eye stands for <strong>honesty, expertise, and success</strong>. With a mission to make global education accessible to everyone, they have become a reliable partner for students looking to build their future across borders.</p>', 1, '2025-10-10 13:28:52', NULL),
('ebe7213a-cbe9-4a90-a48d-7ed4f7fa1ea8', 'Digital Branding & Social Media Campaigns', 'Marketing', 'Social Media', 'Double Morli', 'Service Industries', NULL, 'KERYAR', '2023-11-10', '/images/keryar/portfolio/b97e681b-5983-41b6-b954.jpg', '<p>Our team managed Double Morli’s complete digital presence and branding — from social media identity to creative campaigns and content design. We crafted a vibrant and engaging look across Instagram with colorful visuals, dynamic reels, and appetizing photography.</p><p>We focused on:</p><ul><li><strong>Instagram Marketing:</strong> Showcasing menu highlights, special offers, customer stories, and engaging reels.</li><li><strong>Creative Design:</strong> Appealing layouts, mouthwatering visuals, and catchy copy that reflects freshness and fun.</li><li><strong>Digital Campaigns:</strong> Targeted promotions, festive specials, and influencer collaborations to boost brand reach.</li><li><strong>Community Building:</strong> Interactive stories, polls, and contests to drive engagement and loyalty.</li></ul><p><strong>Brand Outcome:</strong><br>Through a well-planned digital strategy, Double Morli’s online presence evolved into a lively, food-loving brand. Each post reflects the brand’s passion for flavor, community, and the joy of sharing great food together.</p>', 1, '2025-10-11 06:40:14', NULL),
('f1881702-94a6-4a8d-9efa-97f85b05c08c', 'PlantPal – Smart Plant Care Mobile App', 'Development', 'Mobile App', 'PlantPal', 'Service Industries', 'plant care app, plant identification app, mobile ui design, smart gardening app, green lifestyle, plant watering reminder, plant tracker, plant guide app, eco-friendly app design, modern mobile ux', 'KERYAR', '2024-09-10', '/images/keryar/portfolio/4e907e04-bf78-45bd-af3f-a218e52a8308.jpg', '<p><strong>Project Overview:</strong><br>PlantPal is a modern and intuitive mobile application designed for plant lovers who want to easily manage and care for their houseplants. The app helps users identify plants, track watering schedules, and receive care reminders—all wrapped in a simple, elegant design.</p><p><strong>Design Approach:</strong><br>The goal was to create a calm, nature-inspired interface that feels fresh and functional. The use of soft green tones and rounded visuals reflects growth and calmness while maintaining readability. The onboarding flow, task management screens, and photo-based plant identification were designed for effortless usability.</p><p>Each screen is structured for quick understanding—from adding new plants and viewing care tips to tracking water and fertilizer schedules. Friendly illustrations and icons make the experience approachable even for first-time users.</p><p><strong>Development Details:</strong><br>PlantPal was designed with scalability in mind. The UI supports image-based plant recognition, a personal care schedule, and educational tips. The app’s architecture can easily integrate with real-time notification systems for reminders and updates.</p><p><strong>Highlights:</strong></p><ul><li>Fresh and clean green-themed UI for a natural feel</li><li>Simple onboarding with clear CTAs</li><li>“Snap &amp; Identify” feature for plant recognition</li><li>Task reminders for watering and fertilizing</li><li>Customizable care guides and plant profiles</li><li>Fully responsive mobile design for both Android and iOS</li></ul><p><strong>Outcome:</strong><br>The final design delivers a peaceful yet smart digital experience. PlantPal makes plant care easier for beginners and experts alike—turning plant maintenance into a joyful, sustainable daily habit.</p>', 1, '2025-10-31 09:46:56', NULL),
('f19e6017-8830-4cdc-9d5c-11e6b8e77670', 'E-sheba – Online Doctor Consultation & Healthcare Website', 'Development', 'Website', 'E-sheba', 'Healthcare', 'doctor appointment website, healthcare web design, hospital website, medical booking website, telemedicine web design, doctor finder platform, healthcare UI/UX, patient management website, clinic booking system, modern medical website design', 'KERYAR', '2024-10-30', '/images/keryar/portfolio/703adbcb-64a1-4679-90ab-743c3520c242.jpg', '<p><strong>Project Overview:</strong><br>E-sheba is a <strong>modern healthcare website</strong> designed to help patients easily search, find, and book appointments with trusted doctors online. The platform focuses on accessibility, trust, and simplicity — allowing users to connect with specialists anytime, anywhere.</p><p><strong>Design Approach:</strong><br>The layout follows a <strong>clean, clinical, and user-friendly design</strong>, using a calm blue and white palette to evoke trust and professionalism. The homepage introduces the main purpose clearly — <i>“Find &amp; Search Your Favourite Doctor”</i> — with a smart search bar that filters by name and location.</p><p>Key statistics like <strong>24/7 Support</strong>, <strong>100+ Doctors</strong>, and <strong>1M+ Active Patients</strong> immediately build credibility.<br>Below that, visually separated sections highlight:</p><ul><li><strong>Consulting Specialists</strong> (Covid-19, Heart &amp; Lungs, Mental Health, Supplements)</li><li><strong>Reasons to Choose E-sheba</strong> (trust, expertise, and modern service delivery)</li><li><strong>User Reviews</strong> with real member feedback and star ratings</li><li><strong>Newsletter subscription</strong> for ongoing engagement</li></ul><p>The typography is clean and modern, and icons enhance readability without cluttering the interface. Every section is designed to be <strong>visually light yet informative</strong>, ensuring a seamless experience for users of all ages.</p><p><strong>Development Details:</strong><br>The website was built with responsiveness at its core — ensuring smooth performance on mobile, tablet, and desktop. The back-end supports appointment scheduling, doctor profiles, and user authentication for secure patient data management.</p><p><strong>Highlights:</strong></p><ul><li>Doctor search by name, specialty, or location</li><li>Clear and accessible information hierarchy</li><li>Modern and responsive healthcare-focused UI</li><li>Review and rating section for social proof</li><li>Easy appointment booking flow</li><li>Newsletter integration for updates</li><li>SEO-optimized, fast-loading design</li></ul><p><strong>Outcome:</strong><br>E-sheba successfully creates a bridge between doctors and patients in a digital environment. The platform makes healthcare more accessible and convenient while maintaining professionalism, empathy, and trust.</p>', 1, '2025-10-31 10:39:18', NULL),
('fe364f8d-089b-4b41-aa93-8707bd7a1c63', '60-Ball Cricket Branding & Digital Campaigns', 'Marketing', 'Social Media', 'UST10 ', 'Sports', NULL, 'KERYAR', '2024-07-10', '/images/keryar/portfolio/98c7b76f-ad78-4469-9ad9.jpg', '<p>US Masters T10 is redefining cricket in America with its fast-paced, high-energy 60-ball format. Our creative strategy focused on building a compelling brand identity that combines the international spirit of cricket with vibrant American appeal. The visual assets, social campaigns, and storytelling were all crafted to engage fans across the U.S. and beyond, emphasizing speed, excitement, and elite competition.</p><p><strong>Scope of Work:</strong></p><ul><li><strong>Brand Identity &amp; Theme:</strong> Developing a visual language (logo, colors, typography) that blends cricket’s heritage with modern dynamics.</li><li><strong>Match Visuals &amp; Highlight Content:</strong> Designing real-time score graphics, player highlight reels, key moment snippets, and match summaries to keep audiences hooked.</li><li><strong>Player Features:</strong> Spotlighting standout players, their stats, and career highlights — creating emotional connection and narrative around the talent.</li><li><strong>Digital &amp; Social Campaigns:</strong> Teasers, countdowns, match promos, interactive content (polls, predictions) to build buzz and engagement.</li><li><strong>SEO &amp; Content Strategy:</strong> Creating blog content, match recaps, and SEO-optimized pages around keywords like “US Masters T10”, “60-ball cricket USA”, “US cricket tournament”.</li><li><strong>Email Marketing:</strong> Newsletters and campaign emails for fans and subscribers — match schedules, results, featured players, and ticket or streaming info.</li></ul><p><strong>Outcome:</strong><br>The campaign elevated US Masters T10’s brand presence in the U.S. cricket ecosystem, drove fan engagement, and helped position it as a leading 60-ball format tournament in America. The brand identity, content strategy, and community building efforts contributed to stronger visibility and a growing fan base among cricket enthusiasts.</p>', 1, '2025-10-10 11:26:13', '2025-10-10 11:49:10');

